// 跨文化交际 / 概念 content pack.
(function (root, factory) {
  const content = factory();
  if (typeof module !== "undefined" && module.exports) {
    module.exports = content;
  }
  root.reviewContent = { ...(root.reviewContent || {}), ...content };
})(typeof self !== "undefined" ? self : this, function () {
  return {
  "generalizations": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>概括性判断是根据有限观察、资料或经验总结出的群体倾向，用来帮助理解文化差异，但它只能说明可能性，不能当成对每个个体的绝对结论。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Generalizations are based on limited data and then applied to a larger population. In intercultural communication, this means ascribing characteristics to a larger group based on attributes displayed by a smaller group.</p><p>Cultural generalizations should be viewed as approximations, qualified rather than absolute, and supported by a variety of sources.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>概括是基于有限数据并应用到更大人群的判断。在跨文化交际中，它指根据较小群体表现出的特征推断较大群体的特征。</p><p>文化概括应被看作近似判断，需要限定条件，不能绝对化，并应尽量由多种来源支持。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Generalizations are based on limited data and then applied to a larger population.</span>\n        <small class=\"translation\">概括基于有限数据，再应用到更大群体。</small>\n      </li>\n    \n      <li>\n        <span>In intercultural communication, this means ascribing characteristics to a larger group based on attributes displayed by a smaller group.</span>\n        <small class=\"translation\">在跨文化交际中，它指根据较小群体表现出的属性，把特征归于更大群体。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：这是社会科学研究和跨文化分析中的基础方法概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>基于有限数据，却指向较大群体，因此必须承认例外。</span>\n        \n      </li>\n    \n      <li>\n        <span>描述的是 tendency，而不是 law；它是可修正、可验证的分析起点。</span>\n        \n      </li>\n    \n      <li>\n        <span>好的概括会说明范围、条件和证据来源，避免把群体说成完全一致。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际需要一定概括，否则无法预判对方文化中的常见规则。</span>\n        \n      </li>\n    \n      <li>\n        <span>概括可以帮助解释高语境、集体主义、权力距离等文化倾向。</span>\n        \n      </li>\n    \n      <li>\n        <span>使用概括时要不断用具体语境和个体信息修正判断。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>generalization 与 stereotype 的区别最常考：前者开放、可修正；后者僵化、过度简化。</span>\n        \n      </li>\n    \n      <li>\n        <span>看到 limited data、larger group、tendency、pattern，通常是在考 generalization。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题时要加一句：概括不能替代个体差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>概括是理解文化的起点，不是给个人贴标签的终点。</p>\n        </blockquote>\n      </div>\n    ",
  "objectivity": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>客观性指在解释文化现象时尽量基于事实、证据和可观察行为，减少个人情绪、偏见和本文化立场对判断的干扰。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Objectivity means being not influenced by personal feelings, interpretations, or prejudice, and being based on facts.</p><p>It requires approaching each new situation with an open mind, suspending judgment, and learning to value distinct groups regardless of culture, race, ethnicity, religion, country, or gender.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>客观性指判断不受个人感受、解释或偏见影响，而是以事实为基础。</p><p>它要求以开放心态面对新情境，暂缓主观判断，并学习尊重不同文化、种族、族群、宗教、国家或性别群体。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：属于社会科学研究、跨文化观察和批判性思维中的基本原则。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>强调 facts、evidence、observable behavior，而不是第一反应或道德优越感。</span>\n        \n      </li>\n    \n      <li>\n        <span>基本步骤是先描述行为，再解释文化语境，最后谨慎评价。</span>\n        \n      </li>\n    \n      <li>\n        <span>客观不是完全没有立场，而是能意识到自己的文化立场。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，客观性可以减少误解和民族中心主义。</span>\n        \n      </li>\n    \n      <li>\n        <span>面对陌生行为时，应先问“它在对方文化中有什么意义”，而不是立刻判断好坏。</span>\n        \n      </li>\n    \n      <li>\n        <span>客观观察能帮助区分文化差异、个人性格差异和情境差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>objectivity 常与 ethnocentrism 对比考：前者暂停评判，后者以本文化为标准评判他者。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题关键词：facts、evidence、bias、judgment、culture-bound perspective。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把“客观”写成“没有任何价值观”；更准确是意识到并控制偏见。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>先看事实，再看语境，最后才下判断。</p>\n        </blockquote>\n      </div>\n    ",
  "ethnocentrism": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>民族中心主义是以自己的文化作为衡量其他文化的中心标准，并倾向于认为本文化更正常、更正确或更优越。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Ethnocentrism is the habit of overemphasizing one&#39;s own culture as a template for assessing other cultures.</p><p>More specifically, it is the belief that one&#39;s own culture is superior to all others.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>民族中心主义是过度强调自身文化，并把它当作评价其他文化模板的习惯。</p><p>更具体地说，它是一种认为自己的文化优于其他所有文化的信念。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Ethnocentrism is the notion that one&#39;s own culture is superior to any other.</span>\n        <small class=\"translation\">民族中心主义认为自己的文化优于其他任何文化。</small>\n      </li>\n    \n      <li>\n        <span>It measures other cultures by the degree to which they live up to our cultural standards.</span>\n        <small class=\"translation\">它用其他文化符合本文化标准的程度来衡量他文化。</small>\n      </li>\n    \n      <li>\n        <span>We are ethnocentric when viewing other cultures through the narrow lens of our own culture or social position.</span>\n        <small class=\"translation\">当我们通过自身文化或社会位置的狭窄视角看待他文化时，就是民族中心主义。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>William Graham Sumner 常被认为是将 ethnocentrism 系统用于社会科学讨论的重要学者。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>核心是 own culture as the standard。</span>\n        \n      </li>\n    \n      <li>\n        <span>表现为把本文化习惯当作常识，把他文化差异看成落后、奇怪或错误。</span>\n        \n      </li>\n    \n      <li>\n        <span>它可能是显性的文化优越感，也可能隐藏在日常语言和评价中。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>民族中心主义会阻碍倾听、造成误读，并强化偏见和刻板印象。</span>\n        \n      </li>\n    \n      <li>\n        <span>它会让交际者忽略对方行为背后的文化价值和语境。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化能力要求用文化相对主义、客观性和同理心来降低民族中心倾向。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>ethnocentrism 不是单纯热爱本文化，而是用本文化评价并压低其他文化。</span>\n        \n      </li>\n    \n      <li>\n        <span>常见关键词：superior、judge other cultures、own culture、center、normal。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题中看到“他们那样做很没礼貌，因为我们这里不会这样”，多半可分析为民族中心主义。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>把自己的文化当唯一尺子量所有文化，就是 ethnocentrism。</p>\n        </blockquote>\n      </div>\n    ",
  "human-communication": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>人类沟通是人们在特定情境中借助符号创造、分享和解释意义的动态过程。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Human communication is a dynamic process in which people attempt to share their thoughts with other people through the use of symbols in particular settings.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>人类沟通是一个动态过程，在这个过程中，人们在特定情境中借助符号与他人分享自己的想法。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Communication, our ability to share ideas and feelings, is the basis of all human contact.</span>\n        <small class=\"translation\">交际是分享想法和感受的能力，也是所有人类联系的基础。</small>\n      </li>\n    \n      <li>\n        <span>Human communication is a dynamic process in which people attempt to share their thoughts with others through symbols in particular settings.</span>\n        <small class=\"translation\">人类交际是一个动态过程，人们在特定环境中通过符号与他人分享思想。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Elements / 要素</h2>\n        <ul>\n      <li>\n        <span>source</span>\n        <small class=\"translation\">源</small>\n      </li>\n    \n      <li>\n        <span>encoding</span>\n        <small class=\"translation\">编码</small>\n      </li>\n    \n      <li>\n        <span>message</span>\n        <small class=\"translation\">信息</small>\n      </li>\n    \n      <li>\n        <span>channel</span>\n        <small class=\"translation\">信道</small>\n      </li>\n    \n      <li>\n        <span>receiver</span>\n        <small class=\"translation\">接收者</small>\n      </li>\n    \n      <li>\n        <span>decoding</span>\n        <small class=\"translation\">解码</small>\n      </li>\n    \n      <li>\n        <span>feedback</span>\n        <small class=\"translation\">反馈</small>\n      </li>\n    \n      <li>\n        <span>noise</span>\n        <small class=\"translation\">噪声</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Communication is dynamic, symbolic, contextual, self-reflective, irreversible, consequential, and complex.</span>\n        <small class=\"translation\">交际是动态的、符号性的、有语境的、自我反省的、不可逆的、有后果的、复杂的。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-p\">\n        <h2>Functions / 功能</h2>\n        <ul>\n      <li>\n        <span>Communication helps fulfill interpersonal needs.</span>\n        <small class=\"translation\">交际有助于满足人际需求。</small>\n      </li>\n    \n      <li>\n        <span>Communication assists with person perception.</span>\n        <small class=\"translation\">交际有助于人的认知。</small>\n      </li>\n    \n      <li>\n        <span>Communication establishes cultural and personal identities.</span>\n        <small class=\"translation\">交际确立文化身份和个人身份。</small>\n      </li>\n    \n      <li>\n        <span>Communication has persuasive qualities.</span>\n        <small class=\"translation\">交际具有说服力。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：属于传播学基础概念，跨文化交际教材通常把它定义为通过符号分享意义的动态过程。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>dynamic process：沟通不是一次性传递，而是持续变化的互动。</span>\n        \n      </li>\n    \n      <li>\n        <span>symbolic：语言、表情、手势、图像、沉默等都可能承载意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>contextual：意义受到场合、关系、身份、文化和时间影响。</span>\n        \n      </li>\n    \n      <li>\n        <span>meaning-making：沟通的重点不是信息移动，而是意义被共同理解。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化沟通失败常不是因为没有信息，而是因为双方对符号和语境的解释不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解沟通的动态性，有助于在误解出现后通过澄清、反馈和调适修复关系。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际关注的不只是说什么，还包括如何说、谁在说、在什么关系中说。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>答定义时要包含 symbols、meaning、context、dynamic process。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 communication 简化成 message transmission；跨文化课程更重视 meaning interpretation。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题可从 verbal、nonverbal、context、feedback 四个角度分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>communication = symbols + meaning + context + interaction。</p>\n        </blockquote>\n      </div>\n    ",
  "symbol": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>符号是用来代表、表达或传递意义的形式，可以是词语、手势、图像、声音、物品、仪式或行为。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>In human communication, a symbol is an expression that stands for or represents something else.</p><p>Communication involves attaching meaning to symbolic events generated by another person, whether those symbols are intentional or unintentional.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>在人类沟通中，符号是代表或指代其他事物的一种表达形式。</p><p>沟通包含对他人产生的符号性事件赋予意义；这些符号可以是有意的，也可以是无意的。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>A symbol is an expression that stands for or represents something else.</span>\n        <small class=\"translation\">符号是代表或指代其他事物的一种表达。</small>\n      </li>\n    \n      <li>\n        <span>Both intentional and unintentional symbolic events involve attaching meaning to what another person generates.</span>\n        <small class=\"translation\">无论符号事件是有意还是无意，人们都会对他人产生的符号事件附加意义。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Ferdinand de Saussure 和 Charles S. Peirce 是符号学中的重要学者；跨文化交际借用其“符号承载意义”的思路。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>符号与意义之间通常是约定关系，不是天然固定关系。</span>\n        \n      </li>\n    \n      <li>\n        <span>符号意义依赖共享文化规则；同一符号在不同文化中可能意义不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>符号既表达思想，也表达身份、关系、情绪和价值判断。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际本质上是不同符号系统之间的意义协商。</span>\n        \n      </li>\n    \n      <li>\n        <span>误解常来自对同一符号的不同解码，例如手势、颜色、称呼、沉默。</span>\n        \n      </li>\n    \n      <li>\n        <span>学习他文化时要学习符号背后的文化意义，而不仅是表面形式。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>symbol 不是 meaning 本身，而是 meaning 的载体。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言是最重要的符号系统之一，但不是唯一符号系统。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题可写：symbols are culture-bound and learned。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>符号是意义的外壳，文化决定怎样解读它。</p>\n        </blockquote>\n      </div>\n    ",
  "culture": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化是一个群体共享、习得并代际传递的意义系统和生活方式，包括价值观、信念、规范、语言、制度、行为方式和物质产物。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Culture is a set of human-made objective and subjective elements that increased survival and satisfaction in an ecological niche and became shared among people who could communicate with a common language in the same time and place.</p><p>Culture also means that a group has established symbols and rules for using those symbols.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>文化是一组人为创造的客观和主观要素；这些要素曾提升特定生态环境中人们的生存概率和满足感，并在同一时空、使用共同语言的人群中共享。</p><p>文化也意味着一个群体建立了一套符号，以及使用这些符号的规则。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Culture is a set of human-made objective and subjective elements that increased survival and satisfaction in an ecological niche and became shared among people with a common language living in the same time and place.</span>\n        <small class=\"translation\">文化是一组人为的客观和主观因素，它们曾提高特定生态位中的生存可能性和满足感，并在同一时空、使用共同语言的人群中共享。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Function / 功能</h2>\n        <ul>\n      <li>\n        <span>Culture lays out a somewhat predictable world and offers a blueprint for how to behave and what results to anticipate.</span>\n        <small class=\"translation\">文化展示一个相对可预测的世界，并为如何行为以及预期何种结果提供蓝图。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Culture is shared.</span>\n        <small class=\"translation\">文化是共享的。</small>\n      </li>\n    \n      <li>\n        <span>Culture is transmitted from generation to generation.</span>\n        <small class=\"translation\">文化代代相传。</small>\n      </li>\n    \n      <li>\n        <span>Culture is based on symbols.</span>\n        <small class=\"translation\">文化以符号为基础。</small>\n      </li>\n    \n      <li>\n        <span>Culture is learned.</span>\n        <small class=\"translation\">文化是习得的。</small>\n      </li>\n    \n      <li>\n        <span>Culture is dynamic.</span>\n        <small class=\"translation\">文化是动态的。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-p\">\n        <h2>Elements / 要素</h2>\n        <ul>\n      <li>\n        <span>worldview, religion, history, values, social organizations, language, important ideals</span>\n        <small class=\"translation\">世界观、宗教、历史、价值观、社会组织、语言、重要观念。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>经典学者：Edward B. Tylor 给出早期经典定义；Clifford Geertz 强调用意义系统解释文化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>learned：文化通过家庭、教育、语言和社会化获得，不是天生的。</span>\n        \n      </li>\n    \n      <li>\n        <span>shared：文化被群体成员共同理解，但群体内部也有差异。</span>\n        \n      </li>\n    \n      <li>\n        <span>transmitted：文化通过符号和制度传递给下一代。</span>\n        \n      </li>\n    \n      <li>\n        <span>dynamic：文化会随历史、技术、迁移和权力关系变化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化影响人们如何理解自我、关系、时间、空间、权威、礼貌和冲突。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际研究的核心就是文化如何塑造沟通方式和意义解释。</span>\n        \n      </li>\n    \n      <li>\n        <span>不能把文化等同于国家；国家内部也有地区、阶层、族群和代际差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>答定义要写 learned、shared、transmitted、symbolic、dynamic。</span>\n        \n      </li>\n    \n      <li>\n        <span>文化包含主观文化和客观文化：价值信念属于深层，食物服饰属于表层。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题中要解释行为背后的 value、belief、norm，而不是只描述行为。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化是一个群体学会如何生活、解释世界和与人相处的系统。</p>\n        </blockquote>\n      </div>\n    ",
  "world-view": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>世界观是一个文化群体对现实、人性、自然、时间、命运、超自然力量以及人与世界关系的根本看法。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>World view is the way a people interpret reality and events, including their images of themselves and how they relate to the world around them.</p><p>It works as an overarching philosophy of how the world operates and often functions automatically and unconsciously.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>世界观是一个群体解释现实和事件的方式，包括他们如何看待自己，以及如何理解自己与周围世界的关系。</p><p>它像一种关于世界如何运作的总体哲学，常常以自动、无意识的方式发挥作用。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Worldview is the way a people interpret reality and events, including their images of themselves and how they relate to the world around them.</span>\n        <small class=\"translation\">世界观是人们解释现实和事件的方式，包括他们对自身的印象以及与周围世界的关系。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Characteristics and Function / 特点与功能</h2>\n        <ul>\n      <li>\n        <span>Worldviews are automatic and unconscious, like culture itself.</span>\n        <small class=\"translation\">世界观像文化本身一样，常是自动和无意识的。</small>\n      </li>\n    \n      <li>\n        <span>Worldview provides underpinnings for perception and makes sense of life.</span>\n        <small class=\"translation\">世界观为认知和现实体验提供基础，并使生活变得有意义。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：worldview 是人类学、宗教学和跨文化交际中的基础概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>属于深层文化，常常被视为理所当然，不一定被明确说出。</span>\n        \n      </li>\n    \n      <li>\n        <span>影响价值判断、道德判断、行为动机和沟通方式。</span>\n        \n      </li>\n    \n      <li>\n        <span>通常由宗教、哲学、历史经验、家庭教育和社会制度共同塑造。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>世界观差异会影响人们如何看待生死、成功、权威、自然、个人责任和社会关系。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化冲突常不是表层礼仪冲突，而是深层世界观冲突。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解世界观有助于回答“为什么他们会这样沟通和行动”。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>world-view 不等于个人观点，而是群体共享的深层解释框架。</span>\n        \n      </li>\n    \n      <li>\n        <span>它比 cultural values 更深，常为价值观提供基础。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题关键词：reality、human nature、nature、time、supernatural、relationship。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>世界观回答：世界是什么样的，人应该怎样活。</p>\n        </blockquote>\n      </div>\n    ",
  "intercultural-communication-competence": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>跨文化交际能力是在跨文化情境中，能够以有效且恰当的方式理解他者、表达自我、调整行为并实现沟通目标的能力。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Most research on intercultural communication competence includes being motivated, having a fund of knowledge to draw on, and possessing certain communication skills.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>大多数关于跨文化交际能力的研究都包括三个方面：具有交际动机，拥有可调用的知识储备，并具备一定的沟通技能。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Basic Components / 基本组成</h2>\n        <ul>\n      <li>\n        <span>Motivation can be extrinsic or intrinsic.</span>\n        <small class=\"translation\">动机可以是外在的，也可以是内在的。</small>\n      </li>\n    \n      <li>\n        <span>Knowledge works with motivation and requires gathering a fund of knowledge about other cultures.</span>\n        <small class=\"translation\">知识与动机协同发挥作用，要求人们主动积累关于其他文化的知识。</small>\n      </li>\n    \n      <li>\n        <span>Skills are the specific behaviors used to make a communication encounter successful.</span>\n        <small class=\"translation\">技巧是为使交际成功而采取的具体行为。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Knowledge Types / 知识类型</h2>\n        <ul>\n      <li>\n        <span>content knowledge</span>\n        <small class=\"translation\">内容知识</small>\n      </li>\n    \n      <li>\n        <span>procedural knowledge</span>\n        <small class=\"translation\">程序知识</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Exam Focus / 考试重点</h2>\n        <ul>\n      <li>\n        <span>Most research includes motivation, knowledge, and communication skills.</span>\n        <small class=\"translation\">多数研究都把动机、知识和交际技巧作为跨文化交际能力的核心。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Brian Spitzberg 强调有效性和恰当性；Darla Deardorff 强调态度、知识、技能与结果。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>motivation：愿意接触、尊重和理解不同文化的人。</span>\n        \n      </li>\n    \n      <li>\n        <span>knowledge：了解文化模式、语境规则、身份、语言和非语言差异。</span>\n        \n      </li>\n    \n      <li>\n        <span>skills：倾听、观察、解释、移情、调适和处理冲突。</span>\n        \n      </li>\n    \n      <li>\n        <span>effectiveness + appropriateness：既达成目标，又不破坏关系和情境规范。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际能力不是背文化事实，而是在互动中灵活使用知识。</span>\n        \n      </li>\n    \n      <li>\n        <span>它要求既能表达自己，也能理解对方文化中的合适表达方式。</span>\n        \n      </li>\n    \n      <li>\n        <span>高能力者会避免民族中心主义、刻板印象和过度概括。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>常考三要素：motivation、knowledge、communication skills。</span>\n        \n      </li>\n    \n      <li>\n        <span>只会外语不等于有 intercultural competence。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题可写：effective means achieving goals; appropriate means fitting cultural context。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>ICC = 想沟通 + 懂差异 + 会调适。</p>\n        </blockquote>\n      </div>\n    ",
  "deep-culture": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>深层文化是文化中不容易直接观察的价值观、信念、世界观、基本假设和制度逻辑，它解释人们为什么这样行动。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>The key to how members of a culture view the world can be found in that culture&#39;s deep structure.</p><p>Deep structure consists of conscious and unconscious assumptions about how the world works; it unifies a culture, makes it unique, and explains the how and why of collective action.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>理解一个文化成员如何看待世界的关键，可以在该文化的深层结构中找到。</p><p>深层结构由关于世界如何运作的有意识和无意识假设构成；它凝聚文化，使文化具有独特性，并解释集体行动的方式和原因。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Deep structure consists of conscious and unconscious assumptions about how the world works; it unifies a culture, makes it unique, and explains the how and why of collective action.</span>\n        <small class=\"translation\">深层结构由关于世界如何运作的有意识和无意识假设构成；它统一文化、使文化独特，并解释集体行为的方式和原因。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Significance / 意义</h2>\n        <ul>\n      <li>\n        <span>Deep structure institutions transmit culture&#39;s most important messages.</span>\n        <small class=\"translation\">深层结构制度传递文化中最重要的信息。</small>\n      </li>\n    \n      <li>\n        <span>Deep structure institutions and their messages endure.</span>\n        <small class=\"translation\">深层结构制度及其信息经久不衰。</small>\n      </li>\n    \n      <li>\n        <span>Deep structure institutions and their messages are deeply felt.</span>\n        <small class=\"translation\">深层结构制度及其信息令人感触很深。</small>\n      </li>\n    \n      <li>\n        <span>Deep structure institutions supply much of a person&#39;s identity.</span>\n        <small class=\"translation\">深层结构制度在很大程度上塑造个人身份。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Edward T. Hall 等文化研究者常用表层/深层文化区分来解释隐藏的文化规则。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>不可见或半可见：不像食物、节日、服装那样容易观察。</span>\n        \n      </li>\n    \n      <li>\n        <span>稳定而有影响力：长期塑造伦理观、家庭观、权威观、时间观和身份观。</span>\n        \n      </li>\n    \n      <li>\n        <span>通常通过家庭、宗教、教育、社会制度和语言潜移默化地传递。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化误解往往来自深层文化差异，而不只是语言错误。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解深层文化可以解释同一行为在不同文化中为什么有不同意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际分析要从表层行为追问深层价值和假设。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>deep culture 关注 why，不只是 what。</span>\n        \n      </li>\n    \n      <li>\n        <span>可与 surface culture 对比：表层看得见，深层解释行为原因。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题中如涉及面子、权威、家庭责任、时间观，通常可从深层文化分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>表层文化看行为，深层文化看行为背后的理由。</p>\n        </blockquote>\n      </div>\n    ",
  "social-organizations-institutions": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>社会组织或社会制度是文化中稳定组织人际关系、分配角色、规范行为并维持社会秩序的结构，如家庭、教育、宗教、政府、经济和法律制度。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Social organizations, or social institutions, are the groups and affiliations that members of a culture turn to for lessons about the most important aspects of life.</p><p>They create social structure, help members meet basic needs, and coalesce members into a cohesive unit; influential examples include family, state or community, and religion or worldview.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>社会组织或社会制度，是文化成员用来学习生活中最重要方面的群体和归属关系。</p><p>它们创造社会结构，帮助成员满足基本需求，并把成员凝聚成整体；重要例子包括家庭、国家或社区、宗教或世界观。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Social organizations represent the various social units within the culture.</span>\n        <small class=\"translation\">社会组织代表文化中的各种社会单位。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Classification / 分类</h2>\n        <ul>\n      <li>\n        <span>family, government, schools, tribes, clans, and other units</span>\n        <small class=\"translation\">家庭、政府、学校、部落、氏族等社会单位。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Significance / 意义</h2>\n        <ul>\n      <li>\n        <span>Develop patterned interactions and rules.</span>\n        <small class=\"translation\">形成模式化互动和规则。</small>\n      </li>\n    \n      <li>\n        <span>Establish communication networks.</span>\n        <small class=\"translation\">建立交际网络。</small>\n      </li>\n    \n      <li>\n        <span>Cultivate group cohesion.</span>\n        <small class=\"translation\">培养群体凝聚力。</small>\n      </li>\n    \n      <li>\n        <span>Consistently satisfy individual basic needs.</span>\n        <small class=\"translation\">持续满足个人基本需求。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：社会制度是社会学、人类学和跨文化交际共同使用的基础概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>提供身份和归属：人们通过家庭、学校、宗教、职业等获得社会位置。</span>\n        \n      </li>\n    \n      <li>\n        <span>分配角色和责任：规定谁应当做什么、谁有权决定。</span>\n        \n      </li>\n    \n      <li>\n        <span>传递文化规范：制度是文化社会化的重要渠道。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>不同社会制度会塑造不同的沟通规则，如师生关系、亲子关系、职场等级和宗教礼仪。</span>\n        \n      </li>\n    \n      <li>\n        <span>制度差异会影响称呼、礼貌、决策、冲突解决和权力表达。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化案例不能只看个人行为，还要看制度背景。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>institution 不等于建筑物，而是稳定的社会规则和组织方式。</span>\n        \n      </li>\n    \n      <li>\n        <span>family 通常被视为最基本的社会制度。</span>\n        \n      </li>\n    \n      <li>\n        <span>社会制度属于 deep structure of culture 的重要组成部分。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>社会制度把个人组织成有角色、有规则的社会。</p>\n        </blockquote>\n      </div>\n    ",
  "family": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>家庭是基于血缘、婚姻、收养、亲属关系或长期承诺形成的基本社会单位，是个体最早学习文化、语言、身份和关系规则的场所。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>A family is any sexually expressive, parent-child, or other kin relationship in which people, usually related by ancestry, marriage, or adoption, form an economic unit, care for the young, attach their identity to the group, and commit to maintaining that group over time.</p><p>Most people encounter a family of orientation and a family formed when they take a mate; they may also belong to nuclear or extended family patterns.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>家庭是基于性关系、亲子关系或其他亲属关系形成的群体，成员通常通过血缘、婚姻或收养相连，并形成经济单位、照料幼者、把身份与群体相连，且长期维持该群体。</p><p>多数人会经历出身家庭和成年后组建的家庭；同时还可能处于核心家庭或大家庭模式之中。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>A family is a sexually expressive, parent-child, or other kin relationship in which people form an economic unit, care for the young, attach identity to the group, and commit to maintaining it over time.</span>\n        <small class=\"translation\">家庭是性关系、亲子关系或其他亲属关系形成的群体，成员形成经济单位、照顾孩子、把身份与群体相连，并承诺长期维持该群体。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Forms / 分类</h2>\n        <ul>\n      <li>\n        <span>nuclear family: parent or parents and child or children as one unit</span>\n        <small class=\"translation\">核心家庭：父母和孩子构成一个单位。</small>\n      </li>\n    \n      <li>\n        <span>extended family: typically includes grandparents and relatives</span>\n        <small class=\"translation\">大家庭：通常包括祖父母和亲戚。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Functions / 功能</h2>\n        <ul>\n      <li>\n        <span>reproductive, economic, socialization, language acquisition, and identity functions</span>\n        <small class=\"translation\">繁殖功能、经济功能、社会化功能、语言习得功能和身份功能。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-p\">\n        <h2>Significance / 意义</h2>\n        <ul>\n      <li>\n        <span>The family supplies basic physical needs and is the first carrier of essential cultural information.</span>\n        <small class=\"translation\">家庭不仅满足孩子基本物质需求，也是孩子作为文化成员所需重要信息的第一个载体。</small>\n      </li>\n    \n      <li>\n        <span>Cultural variants include gender roles, individualism and collectivism, individualism and the family, and collectivism and the family.</span>\n        <small class=\"translation\">家庭互动的文化变体包括性别角色、个人主义与集体主义、个人主义家庭观和集体主义家庭观。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：家庭是人类学、社会学和跨文化交际中的基础社会制度概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>承担照料、经济支持、情感支持和社会化功能。</span>\n        \n      </li>\n    \n      <li>\n        <span>传递语言、价值观、礼貌规则、宗教信念、性别角色和家庭责任观。</span>\n        \n      </li>\n    \n      <li>\n        <span>家庭边界因文化而异，有些强调核心家庭，有些强调大家庭和亲属网络。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>家庭观影响个人独立、婚姻选择、代际关系、养老责任和亲属称呼。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中，家庭责任可能影响决策、时间安排和个人目标。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解家庭制度有助于解释个体主义/集体主义差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>family of orientation 是出生和成长的家庭；family of procreation 是成年后组建的家庭。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把西方核心家庭模式当成所有文化的标准。</span>\n        \n      </li>\n    \n      <li>\n        <span>家庭既是私人关系，也是文化制度。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>家庭是一个人最早进入文化的地方。</p>\n        </blockquote>\n      </div>\n    ",
  "individual-collective-dimension": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>个体主义/集体主义维度描述一个文化更强调个人独立、自我表达和个人目标，还是更强调群体归属、相互依赖和群体利益。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>The individual-collective dimension is a culture&#39;s tendency to encourage people to be unique and independent or conforming and interdependent.</p><p>Individualistic cultures value the individual over the group; collective cultures emphasize the needs and goals of the group and view people primarily as members of groups and collectives.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>个体主义/集体主义维度指一种文化倾向于鼓励人们独特、独立，还是顺从、相互依赖。</p><p>个体主义文化重视个人高于群体；集体主义文化强调群体的需求和目标，并把人主要看作群体或集体的成员。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Collectivism / 集体主义</h2>\n        <ul>\n      <li>\n        <span>Collectivism is a culture&#39;s tendency to encourage people to be conforming and interdependent.</span>\n        <small class=\"translation\">集体主义是鼓励人们遵从并相互依存的文化倾向。</small>\n      </li>\n    \n      <li>\n        <span>Collective cultures emphasize group needs and goals, interdependence, group achievement, and cooperation.</span>\n        <small class=\"translation\">集体主义文化强调群体需求和目标、相互依赖、群体成就与合作。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Individualism / 个人主义</h2>\n        <ul>\n      <li>\n        <span>Individualism is a culture&#39;s tendency to encourage people to be unique and independent.</span>\n        <small class=\"translation\">个人主义是鼓励人们独特和独立的文化倾向。</small>\n      </li>\n    \n      <li>\n        <span>Individualistic cultures value uniqueness, independence, competition, self-determination, individual goals, and the I as a core identity.</span>\n        <small class=\"translation\">个人主义文化重视独特性、独立、竞争、自我决定、个人目标，以及以“我”为核心的身份。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Geert Hofstede 将 individualism/collectivism 列为文化维度；Harry Triandis 对个体主义和集体主义做了重要扩展。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>individualism：强调个人权利、选择、自我实现、隐私和个人责任。</span>\n        \n      </li>\n    \n      <li>\n        <span>collectivism：强调群体和谐、忠诚、责任、关系网络和相互依赖。</span>\n        \n      </li>\n    \n      <li>\n        <span>这一维度影响自我介绍、决策方式、冲突处理、赞扬批评和礼貌策略。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>个体主义文化中，直接表达个人意见可能被看作诚实和自信。</span>\n        \n      </li>\n    \n      <li>\n        <span>集体主义文化中，维护关系和避免让群体丢面子可能比个人表达更重要。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化沟通时要判断对方更重个人立场还是群体关系。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>它描述文化倾向，不代表每个个体都一样。</span>\n        \n      </li>\n    \n      <li>\n        <span>集体主义不等于没有个人，个体主义也不等于自私。</span>\n        \n      </li>\n    \n      <li>\n        <span>常与 high-context、facework、family responsibility 一起考。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>个人优先看 individualism，群体优先看 collectivism。</p>\n        </blockquote>\n      </div>\n    ",
  "perception": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>感知是人们选择、组织并解释信息，从而理解世界和建构现实的过程。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Perception is how we make sense of the world and how we construct reality.</p><p>The process involves selectively attending to stimuli, organizing or categorizing selected information, and assigning meaning; sociocultural factors such as beliefs, values, and attitudes provide templates for that meaning.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>感知是我们理解世界、建构现实的方式。</p><p>这一过程包括有选择地注意刺激、组织或分类被选择的信息，并赋予意义；信念、价值观和态度等社会文化因素会为意义解释提供模板。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Perception is selective.</span>\n        <small class=\"translation\">认知是有选择性的。</small>\n      </li>\n    \n      <li>\n        <span>Perception is learned.</span>\n        <small class=\"translation\">认知是后天习得的。</small>\n      </li>\n    \n      <li>\n        <span>Perception is culturally determined.</span>\n        <small class=\"translation\">认知由文化决定。</small>\n      </li>\n    \n      <li>\n        <span>Perception is consistent.</span>\n        <small class=\"translation\">认知具有一致性，一旦形成解释通常不易改变。</small>\n      </li>\n    \n      <li>\n        <span>Perception is inaccurate.</span>\n        <small class=\"translation\">认知并不完全准确，人们会通过受文化、价值观和经历影响的主观镜头看世界。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：感知是心理学和传播学基础概念，跨文化交际强调文化会影响感知过程。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>selection：人们会选择注意某些信息，忽略另一些信息。</span>\n        \n      </li>\n    \n      <li>\n        <span>organization：人们会把信息分类、排序并放入已有认知框架。</span>\n        \n      </li>\n    \n      <li>\n        <span>interpretation：人们根据经验、文化、情绪和语境解释意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>感知具有文化性和主观性，不是对现实的完全复制。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>同一行为在不同文化感知中可能被解释为礼貌、冷淡、冒犯或真诚。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化误解常来自感知差异，而不是事实本身不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>提高跨文化能力需要意识到自己的感知过滤器。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>三步：selection、organization、interpretation。</span>\n        \n      </li>\n    \n      <li>\n        <span>perception 不是被动接收，而是主动建构。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题可写：culture shapes what we notice and how we interpret it。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>我们不是直接看见世界，而是通过文化理解世界。</p>\n        </blockquote>\n      </div>\n    ",
  "belief": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>信念是人们认为真实、正确或可信的观念，可以来自经验、宗教、教育、传统、媒体或社会群体。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>A belief is a concept or idea that an individual or group holds to be true.</p><p>Beliefs represent subjective conviction in the truth of something, with or without proof; shared beliefs can become cultural norms or values.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>信念是个人或群体认为真实的概念或观念。</p><p>信念代表人们对某事为真的主观确信，不论是否有证据；被共享的信念可能发展为文化规范或价值观。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>A belief is a concept or idea that an individual or group holds to be true.</span>\n        <small class=\"translation\">信念是个人或群体认为真实的概念或想法。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Beliefs represent subjective conviction in the truth of something, with or without proof.</span>\n        <small class=\"translation\">信念代表我们对某事真实性的主观确信，无论是否有证据。</small>\n      </li>\n    \n      <li>\n        <span>Shared beliefs can represent cultural norms and values.</span>\n        <small class=\"translation\">共同信念可以代表文化规范和价值观。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Function / 功能</h2>\n        <ul>\n      <li>\n        <span>Beliefs can associate people with like-minded individuals and reinforce conviction.</span>\n        <small class=\"translation\">信念可以使人们与志同道合者联系，并强化确信感。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：信念是心理学、社会学和文化研究中的基础概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>信念不一定有客观证据，但会真实影响人的判断和行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>当信念被群体共享并代际传递时，就会成为文化的一部分。</span>\n        \n      </li>\n    \n      <li>\n        <span>信念常为价值观提供基础，例如对人性、命运、家庭或权威的看法。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>不同信念会影响人们如何解释疾病、成功、责任、婚姻、教育和礼貌。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交流中，如果只反驳对方行为而不理解其信念基础，容易引发冲突。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解信念有助于解释文化价值观和行为规范。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>belief 关注 true/false 的确信；value 关注 good/bad、important/unimportant 的判断。</span>\n        \n      </li>\n    \n      <li>\n        <span>信念不等于事实，但会驱动行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例中看到“他们相信……”通常可归入 belief。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>belief 是“我认为这是真的”。</p>\n        </blockquote>\n      </div>\n    ",
  "cultural-values": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化价值观是一个文化群体共享的关于好坏、对错、重要与不重要、值得追求与应当避免的判断标准。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Beliefs form the foundation of values; what people consider desirable for themselves and their society is a product of their values.</p><p>Cultural values provide guidelines for deciding what is good or bad, desirable or undesirable, right or wrong, and appropriate or inappropriate in human activity.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>信念构成价值观的基础；人们认为对自己和社会而言什么是可取的，来自其价值观。</p><p>文化价值观为人们判断人类活动中什么是好坏、可取或不可取、对错、合适或不合适提供准则。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>What people consider desirable for themselves and for society is a product of values.</span>\n        <small class=\"translation\">人们认为对自己和社会而言可取的东西，是价值观的产物。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Values are broad-based, enduring, relatively stable, and operate consciously and subconsciously.</span>\n        <small class=\"translation\">价值观基础广泛、经久稳定，并在有意识和潜意识层面发挥作用。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Function and Significance / 功能与意义</h2>\n        <ul>\n      <li>\n        <span>Values permeate and characterize a culture.</span>\n        <small class=\"translation\">价值观渗透并表征文化。</small>\n      </li>\n    \n      <li>\n        <span>Cultural values establish expected behavior modes and criteria for judging conduct.</span>\n        <small class=\"translation\">文化价值观建立行为模式和评价行为的标准。</small>\n      </li>\n    \n      <li>\n        <span>They help members decide what is good or bad, right or wrong, appropriate or inappropriate.</span>\n        <small class=\"translation\">它们帮助文化成员判断好坏、对错、合适与否。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Kluckhohn 与 Strodtbeck 的 value orientations 研究，以及 Hofstede 的文化维度都与文化价值观分析有关。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>价值观建立在共享信念之上，并为行为选择提供方向。</span>\n        \n      </li>\n    \n      <li>\n        <span>价值观相对稳定，会通过家庭、教育、制度和语言传递。</span>\n        \n      </li>\n    \n      <li>\n        <span>价值观常体现在礼貌规范、决策方式、冲突处理和社会评价中。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>不同文化价值观会影响人们对独立、和谐、权威、效率、面子、时间和成功的理解。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化冲突常发生在价值优先级不同的时候。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解文化价值观可以解释表面行为背后的判断标准。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>value 不是个人偏好，而是群体层面的指导原则。</span>\n        \n      </li>\n    \n      <li>\n        <span>belief 是“什么是真的”，value 是“什么是重要/好的”。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题时可把 values 与 behaviors 连起来：values guide behaviors。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>value 是文化告诉人们什么值得追求。</p>\n        </blockquote>\n      </div>\n    ",
  "behaviors": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>行为是人们在具体情境中表现出来的语言行动、非语言行动和社会行动，是信念、价值观、规范和身份在交际中的外在体现。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Behaviors are the outward manifestations of internalized beliefs and values.</p><p>Culture has a regulatory influence on behavior by defining accepted deportment in different social contexts and specifying age-appropriate and gender-specific conduct.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>行为是内化的信念和价值观的外在表现。</p><p>文化会调节行为，规定不同社会情境中被接受的举止，并界定符合年龄和性别期待的行为。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Behaviors are the outward manifestations of internalized beliefs and values.</span>\n        <small class=\"translation\">行为是内化的信念和价值观的外在表现。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Relation to Culture / 与文化的关系</h2>\n        <ul>\n      <li>\n        <span>Culture has a regulatory influence on behaviors.</span>\n        <small class=\"translation\">文化对行为具有调节和规范作用。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Relation to ICC / 与跨文化交际的关系</h2>\n        <ul>\n      <li>\n        <span>Beliefs and values exert influence on people&#39;s communicative behaviors.</span>\n        <small class=\"translation\">信念和价值观会影响人们的交际行为。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：行为是跨文化交际中观察文化差异的基本层面。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>行为是可观察的，但其意义需要结合文化语境解释。</span>\n        \n      </li>\n    \n      <li>\n        <span>同一行为在不同文化中可能有不同合适性和不同含义。</span>\n        \n      </li>\n    \n      <li>\n        <span>行为受文化、个人性格、关系、身份、权力和场合共同影响。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际不能只看行为本身，还要问行为在该文化中意味着什么。</span>\n        \n      </li>\n    \n      <li>\n        <span>非语言行为如眼神、距离、沉默、触碰尤其容易造成误解。</span>\n        \n      </li>\n    \n      <li>\n        <span>分析行为要避免从一次经历推断整个文化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>behavior 是外在表现；belief/value 是内在原因。</span>\n        \n      </li>\n    \n      <li>\n        <span>不能只凭一次行为判断整个群体。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题应从 visible behavior 追溯 invisible values。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>行为是价值观落到具体场景里的样子。</p>\n        </blockquote>\n      </div>\n    ",
  "cultural-patterns-value-orientations": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化模式或价值取向是一组相互关联的主流价值、信念和行为倾向，用来概括一个文化处理关键问题的方式。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Cultural patterns, sometimes called value orientations, are an umbrella term for cultural values that characterize the dominant group within a culture.</p><p>They refer to culturally based beliefs, values, attitudes, and behaviors shared by members of a particular culture; these patterns are integrated, dynamic, and sometimes contradictory.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>文化模式，有时也叫价值取向，是用来概括一个文化中主导群体文化价值观的总称。</p><p>它指特定文化成员共享的、以文化为基础的信念、价值观、态度和行为；这些模式相互关联、动态变化，也可能存在矛盾。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Cultural patterns, sometimes called value orientations, collectively describe the cultural values of the dominant group within a culture.</span>\n        <small class=\"translation\">文化模式，有时称为价值取向，是用来整体描述某一文化中主导群体文化价值观的术语。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Cultural patterns are integrated.</span>\n        <small class=\"translation\">文化模式是综合的、相互关联的。</small>\n      </li>\n    \n      <li>\n        <span>Cultural patterns are dynamic.</span>\n        <small class=\"translation\">文化模式是动态的。</small>\n      </li>\n    \n      <li>\n        <span>Cultural patterns can be contradictory.</span>\n        <small class=\"translation\">文化模式可能相互矛盾。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Kluckhohn 与 Strodtbeck 提出价值取向框架；Hofstede、Hall 等也提供文化模式分析工具。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它关注文化如何回答人性、人与自然、时间、活动、人际关系等基本问题。</span>\n        \n      </li>\n    \n      <li>\n        <span>文化模式是对主流倾向的概括，不是每个个体的固定属性。</span>\n        \n      </li>\n    \n      <li>\n        <span>不同文化模式之间相互关联，也可能在同一文化内部存在矛盾。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化模式为分析跨文化差异提供框架，例如高低语境、权力距离、时间取向。</span>\n        \n      </li>\n    \n      <li>\n        <span>它帮助解释沟通方式、冲突处理、组织管理和人际关系差异。</span>\n        \n      </li>\n    \n      <li>\n        <span>使用文化模式时要避免标签化和决定论。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>value orientations 强调文化如何选择优先价值。</span>\n        \n      </li>\n    \n      <li>\n        <span>它是分析工具，不是给国家或个人下绝对结论。</span>\n        \n      </li>\n    \n      <li>\n        <span>可与 Hofstede dimensions、Hall context/time orientation 联系答题。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化模式是理解差异的地图，不是每个人的身份证。</p>\n        </blockquote>\n      </div>\n    ",
  "high-context-low-context": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>高语境/低语境区分信息主要依赖语境、关系和共享背景来理解，还是主要依赖明确、直接的语言文字来理解。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>In high-context communication, much of the information is already in the person or context, while very little is in the explicit coded message.</p><p>In low-context communication, most information is vested in the explicit code; high-context cultures rely more on context, inference, gestures, and what is not said, while low-context cultures rely more on words.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>在高语境沟通中，大量信息已经存在于人、关系或语境之中，明确编码的话语只承载较少信息。</p><p>在低语境沟通中，大部分信息依靠明确编码的语言来传递；高语境文化更依赖语境、推断、手势和未说出口的内容，低语境文化更依赖语言文字。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>In high-context communication, most information is already in the person and little is in the explicit code.</span>\n        <small class=\"translation\">高语境交际中，大部分信息已经存在于人和语境中，明确编码的信息较少。</small>\n      </li>\n    \n      <li>\n        <span>Low-context communication is the opposite: most information is vested in the explicit code.</span>\n        <small class=\"translation\">低语境交际正相反，大部分信息归属于明确代码。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>High-context cultures rely on context; low-context cultures rely on words.</span>\n        <small class=\"translation\">高语境文化依赖语境，低语境文化依赖文字和话语。</small>\n      </li>\n    \n      <li>\n        <span>High-context meaning is often not communicated through words.</span>\n        <small class=\"translation\">高语境中的大部分意义往往不通过语言直接传达。</small>\n      </li>\n    \n      <li>\n        <span>Low-context cultures often have more population diversity and compartmentalized interpersonal contacts.</span>\n        <small class=\"translation\">低语境文化通常人口多样性较高，人际联系也更分区化。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Function / 功能</h2>\n        <ul>\n      <li>\n        <span>High-context cultures usually have similarity among members, creating shared perceptions, experiences, expectations, and social protocol.</span>\n        <small class=\"translation\">高语境文化成员相似性较高，形成共享的感知、经验、期待和社会礼仪。</small>\n      </li>\n    \n      <li>\n        <span>People in high-context cultures can express and interpret emotions nonverbally more easily.</span>\n        <small class=\"translation\">高语境文化中的人更容易用非语言方式表达和解释情绪。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Edward T. Hall。该理论属于 Hall 对文化与沟通方式研究的重要内容。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>high-context：含蓄、间接、重关系、重身份、重非语言线索和共享背景。</span>\n        \n      </li>\n    \n      <li>\n        <span>low-context：直接、明确、重文字、重规则、重信息完整和清楚表达。</span>\n        \n      </li>\n    \n      <li>\n        <span>高低不是价值高低，而是信息分布方式不同。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>高语境沟通中，不理解关系、沉默、语气和场合就可能误读信息。</span>\n        \n      </li>\n    \n      <li>\n        <span>低语境沟通中，如果表达不够明确，对方可能认为信息不足或不专业。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中要判断“意思在话里”还是“意思在语境里”。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>Hall，不是 Hofstede。</span>\n        \n      </li>\n    \n      <li>\n        <span>合同、说明书、会议纪要、直接表达常对应低语境。</span>\n        \n      </li>\n    \n      <li>\n        <span>暗示、面子、关系、沉默、非语言线索常对应高语境。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>高语境：意思在场景和关系里；低语境：意思在语言和文字里。</p>\n        </blockquote>\n      </div>\n    ",
  "context": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>语境是沟通发生并被解释的背景条件，包括语言、物理、社会、文化、心理、时间、关系和交际目的等因素。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Hall saw context as the information that surrounds an event.</p><p>His work showed that cultures are often characterized by high-context or low-context communication.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>霍尔把语境看作围绕某个事件的信息。</p><p>他的研究表明，文化常常可以用高语境或低语境沟通来描述。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：语境是传播学和语言学基础概念；Hall 的高低语境理论使其在跨文化交际中尤其重要。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>语言语境：前后文和话语内容。</span>\n        \n      </li>\n    \n      <li>\n        <span>物理语境：地点、空间、环境和场合。</span>\n        \n      </li>\n    \n      <li>\n        <span>社会文化语境：身份、关系、权力、价值观、习俗和禁忌。</span>\n        \n      </li>\n    \n      <li>\n        <span>心理和时间语境：情绪、意图、时机、历史背景。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>同一句话在不同语境中可能是称赞、讽刺、请求或批评。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中，语境判断不同会导致礼貌、距离、沉默、拒绝方式被误解。</span>\n        \n      </li>\n    \n      <li>\n        <span>高语境文化更依赖语境，低语境文化相对更依赖明确语言。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>context 不只是 co-text；co-text 是语言上下文，context 范围更广。</span>\n        \n      </li>\n    \n      <li>\n        <span>context 不等于 culture；culture 是语境的重要组成部分。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题关键词：background、setting、relationship、participants、meaning interpretation。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>语境决定意义，同一句话换个场合就可能换个意思。</p>\n        </blockquote>\n      </div>\n    ",
  "uncertainty-avoidance": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>不确定性规避指一个文化中的成员面对不确定、模糊、未知和不可预测情境时感到焦虑或不适的程度。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Uncertainty avoidance is the extent to which members of a culture feel threatened by ambiguous or unknown situations.</p><p>High uncertainty avoidance cultures reduce unpredictability through rules, regulations, planning, rituals, and established conventions; low uncertainty avoidance cultures accept uncertainty more easily and tend to be flexible, tolerant, and less constrained by social protocol.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>不确定性规避指一种文化的成员在多大程度上会受到模糊或未知情境的威胁。</p><p>高不确定性规避文化通过规则、制度、计划、仪式和既定惯例来减少不可预测性；低不确定性规避文化更容易接受不确定性，更灵活、宽容，也较少受社会礼仪束缚。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Uncertainty avoidance is the extent to which members of a culture feel threatened by ambiguous or unknown situations.</span>\n        <small class=\"translation\">不确定性规避指文化成员在模糊或未知情境中感到威胁的程度。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>High Uncertainty Avoidance / 高不确定性规避</h2>\n        <ul>\n      <li>\n        <span>High uncertainty avoidance cultures reduce unpredictability and ambiguity through intolerance of deviant ideas, consensus, resistance to change, and traditional protocols.</span>\n        <small class=\"translation\">高不确定性规避文化通过不容忍偏差观点、强调共识、抵制变化和坚持传统礼仪来减少不可预测性和模糊性。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Low Uncertainty Avoidance / 低不确定性规避</h2>\n        <ul>\n      <li>\n        <span>Low uncertainty avoidance cultures accept uncertainty more easily, tolerate the unusual, value initiative, dislike hierarchy-related structure, take risks, and prefer fewer rules.</span>\n        <small class=\"translation\">低不确定性规避文化更容易接受不确定，容忍异常，重视主动性，不喜欢等级结构，愿意冒险，并倾向较少规则。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Geert Hofstede。属于 Hofstede cultural dimensions theory。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>高不确定性规避：重规则、计划、稳定、安全、明确流程和标准答案。</span>\n        \n      </li>\n    \n      <li>\n        <span>低不确定性规避：更能接受模糊、变化、弹性、探索和非正式安排。</span>\n        \n      </li>\n    \n      <li>\n        <span>它关注 ambiguity 和 uncertainty，不只是普通风险。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>课堂中，高不确定性规避者可能希望老师明确评分标准和任务要求。</span>\n        \n      </li>\n    \n      <li>\n        <span>职场中，高不确定性规避文化可能更依赖制度、合同、流程和审批。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化合作时，双方对计划和临时变化的接受度不同，容易产生摩擦。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>Hofstede，不是 Hall。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 uncertainty avoidance 写成 risk avoidance；重点是对模糊未知的不适。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 power distance 区分：前者看未知和规则，后者看等级和权威。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>怕模糊、要规则，是高不确定性规避。</p>\n        </blockquote>\n      </div>\n    ",
  "power-distance": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>权力距离指社会中权力较小的成员接受并期待权力不平等分配的程度。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Power distance concerns how societies manage the fact that people are unequal.</p><p>It is the extent to which the less powerful members of institutions and organizations within a country expect and accept that power is distributed unequally.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>权力距离关注社会如何处理人们并不平等这一事实。</p><p>它指一个国家内机构和组织中权力较小的成员，对权力不平等分配的期待和接受程度。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Power distance is the extent to which less powerful members of institutions and organizations expect and accept unequal power distribution.</span>\n        <small class=\"translation\">权力距离是机构和组织中权力较小成员对权力不平等分配的期待和接受程度。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>High Power Distance / 高权力距离</h2>\n        <ul>\n      <li>\n        <span>Members accept power as part of society and learn that people are not equal; hierarchy may be based on family name, education, age, profession, or organizational position.</span>\n        <small class=\"translation\">成员接受权力是社会的一部分，并学习到人并不平等；等级可能基于姓氏、教育、年龄、职业或组织职位。</small>\n      </li>\n    \n      <li>\n        <span>Organizations commonly centralize power, recognize rank and status, follow authority lines, and make more authoritarian decisions.</span>\n        <small class=\"translation\">组织通常权力集中，认可等级与地位，遵守权威路线，决策更具权威性。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Low Power Distance / 低权力距离</h2>\n        <ul>\n      <li>\n        <span>Low power distance cultures minimize inequality, treat subordinates and superiors as equals, deemphasize titles, and prefer consultative consensus decision making.</span>\n        <small class=\"translation\">低权力距离文化尽量减少不平等，下级和上级平等相待，不强调头衔，并倾向协商式共识决策。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Geert Hofstede。属于 Hofstede cultural dimensions theory。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>高权力距离：等级明显、尊重权威、重身份头衔、下级较少公开挑战上级。</span>\n        \n      </li>\n    \n      <li>\n        <span>低权力距离：强调平等、参与、协商、反馈和质疑权威。</span>\n        \n      </li>\n    \n      <li>\n        <span>定义重点是 less powerful members 是否接受不平等，而不只是掌权者是否强势。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>影响师生关系、亲子关系、职场沟通、会议发言和决策方式。</span>\n        \n      </li>\n    \n      <li>\n        <span>高权力距离文化中，直接反驳老师或老板可能被视为不尊重。</span>\n        \n      </li>\n    \n      <li>\n        <span>低权力距离文化中，不表达意见可能被视为缺乏参与。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>power distance 不是 physical distance，也不是 proxemics。</span>\n        \n      </li>\n    \n      <li>\n        <span>常见关键词：hierarchy、authority、status、titles、obedience、participation。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 uncertainty avoidance 区分：权力距离看等级，不确定性规避看模糊。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>认等级、敬权威，是高权力距离。</p>\n        </blockquote>\n      </div>\n    ",
  "masculinity-femininity": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>男性化/女性化维度描述一个文化更重视竞争、成就、果断和物质成功，还是更重视关怀、合作、谦逊和生活质量。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Hofstede uses masculinity and femininity to refer to the degree to which masculine or feminine traits are valued and revealed.</p><p>Masculinity emphasizes assertiveness, toughness, and material success; femininity emphasizes modesty, tenderness, care, and quality of life for both men and women.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>霍夫斯泰德用男性化和女性化来指男性化或女性化特质被重视和展现的程度。</p><p>男性化强调果断、强硬和物质成功；女性化强调男女都应谦逊、温和、关怀他人并重视生活质量。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Geert Hofstede。属于 Hofstede cultural dimensions theory。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>masculinity：achievement、competition、assertiveness、success、material rewards。</span>\n        <small class=\"translation\">男性化：成就、竞争、果断、成功和物质回报。</small>\n      </li>\n    \n      <li>\n        <span>femininity：care、cooperation、modesty、quality of life、work-life balance。</span>\n        <small class=\"translation\">女性化：关怀、合作、谦逊、生活质量和工作生活平衡。</small>\n      </li>\n    \n      <li>\n        <span>它讨论社会价值取向，不是男女数量，也不是简单的男性统治或女性统治。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>影响职场评价、课堂竞争、冲突处理、赞美方式和成功观。</span>\n        \n      </li>\n    \n      <li>\n        <span>男性化文化中，直接竞争和突出成绩可能更被鼓励。</span>\n        \n      </li>\n    \n      <li>\n        <span>女性化文化中，照顾感受、维护平衡和合作更受重视。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>Hofstede 维度之一。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要与 gender 混淆；gender 是社会性别身份和角色，masculinity/femininity 是文化价值取向。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要与 individualism/collectivism 混淆；前者看竞争/关怀，后者看个人/群体。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>重竞争和成功是男性化，重关怀和生活质量是女性化。</p>\n        </blockquote>\n      </div>\n    ",
  "face-facework": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>面子是人在互动中希望维持的社会形象、尊严和被认可感；面子功夫是维护、保护、挽回或给予面子的沟通策略。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Face is the public self-image a person projects to other people, or how one is perceived by others.</p><p>Facework refers to coordinated practices through which communicators build, maintain, protect, threaten, acquire, or give face.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>面子是一个人向他人呈现的公共自我形象，也就是别人如何看待你。</p><p>面子功夫指交际者用来建立、维持、保护、威胁、获得或给予面子的一系列协调性沟通实践。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Face / 面子</h2>\n        <ul>\n      <li>\n        <span>Face is the self-image a person projects to other people.</span>\n        <small class=\"translation\">面子是一个人向他人展示的自我形象。</small>\n      </li>\n    \n      <li>\n        <span>In collectivistic cultures, group membership is a major source of identity and status and helps sustain harmonious in-group relationships.</span>\n        <small class=\"translation\">在集体主义文化中，群体成员身份通常是身份和地位的主要来源，并有助于维持稳定和谐的内群体关系。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Facework / 面子功夫</h2>\n        <ul>\n      <li>\n        <span>Facework consists of actions used to acquire or maintain face for oneself or give face to someone else.</span>\n        <small class=\"translation\">面子功夫是为自己获得或维持面子，或给予他人面子而采取的行动。</small>\n      </li>\n    \n      <li>\n        <span>Collectivists often prefer avoidance and obligating measures in conflict because they consider mutual face and others&#39; face.</span>\n        <small class=\"translation\">面对冲突时，集体主义者常倾向回避和迁就，因为他们关注彼此面子和他人面子。</small>\n      </li>\n    \n      <li>\n        <span>Individualists tend to focus on self-face and favor confrontational, solution-oriented approaches.</span>\n        <small class=\"translation\">个人主义者更关注自我面子，倾向对抗性和问题解决导向的方法。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Erving Goffman 系统讨论 face-work；Stella Ting-Toomey 将 face 与跨文化冲突和 face-negotiation theory 联系起来。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>face 涉及自尊、体面、社会身份、他人评价和关系秩序。</span>\n        \n      </li>\n    \n      <li>\n        <span>facework 包括道歉、委婉表达、回避公开冲突、给台阶、解释和补救。</span>\n        \n      </li>\n    \n      <li>\n        <span>面子既可以是自己的形象，也可以是对方或群体的形象。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>高语境和集体主义文化中，面子管理常与关系和群体和谐密切相关。</span>\n        \n      </li>\n    \n      <li>\n        <span>公开批评、直接拒绝、当众纠错可能构成 face-threatening act。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解面子有助于解释间接表达、沉默、委婉拒绝和冲突回避。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>face 不是简单 vanity，而是互动中的公共社会形象。</span>\n        \n      </li>\n    \n      <li>\n        <span>facework 是策略，不是面子本身。</span>\n        \n      </li>\n    \n      <li>\n        <span>常与 high-context、collectivism、politeness、conflict style 一起考。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>面子是形象，面子功夫是保护形象的沟通动作。</p>\n        </blockquote>\n      </div>\n    ",
  "social-identities": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>社会身份是个体基于群体成员资格形成的自我认同和他人认知，如国籍、民族、性别、宗教、阶层、职业、年龄和语言群体。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Social identities are represented by the many groups you belong to, such as racial, ethnic, occupational, age, hometown, and other groups.</p><p>They result from being a member of some social groups and a nonmember of others.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>社会身份由你所属的许多群体来体现，例如种族、族群、职业、年龄、家乡等群体。</p><p>它来自一个人属于某些社会群体，同时不属于另一些社会群体这一事实。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Henri Tajfel 和 John Turner 的 Social Identity Theory 强调群体归属对自我概念的影响。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>来自 group membership，并与归属感、评价和情感意义相关。</span>\n        \n      </li>\n    \n      <li>\n        <span>一个人同时拥有多重社会身份，且不同情境会激活不同身份。</span>\n        \n      </li>\n    \n      <li>\n        <span>社会身份可能带来资源、权力、期待，也可能带来偏见和限制。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，人们常先通过社会身份理解对方，例如国籍、口音、族群或性别。</span>\n        \n      </li>\n    \n      <li>\n        <span>社会身份影响称呼、礼貌、话语权、被信任程度和被刻板化的风险。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解多重身份有助于避免把一个人简化成单一群体标签。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>social identity 回答“我属于哪些群体”。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 personal identity 区分：社会身份强调群体归属，个人身份强调独特经历和个性。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例中涉及群体标签、身份归属、权力差异时可用该概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>社会身份是“我属于哪些群体”。</p>\n        </blockquote>\n      </div>\n    ",
  "personal-identity": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>个人身份是个体对自身独特性的理解，包括性格、经历、能力、兴趣、价值选择、人生故事和自我定位。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Personal identity is what sets you apart from other in-group members and marks you as special or unique.</p><p>It can come from innate talent, special achievement, or intangible traits such as personality.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>个人身份是使你区别于内群体其他成员，并标记你特殊性或独特性的东西。</p><p>它可以来自天赋、特殊成就，也可以来自性格等无形特质。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：常与社会身份理论、自我概念研究和跨文化身份研究一起讨论。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>强调 uniqueness 和 personal history。</span>\n        \n      </li>\n    \n      <li>\n        <span>会受到文化和社会身份影响，但不能被群体标签完全替代。</span>\n        \n      </li>\n    \n      <li>\n        <span>个人身份会随经历、关系和跨文化接触不断变化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，不能只用国籍、民族或性别推断一个人的全部行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>尊重个人身份意味着允许对方自我定义，而不是只按群体标签理解对方。</span>\n        \n      </li>\n    \n      <li>\n        <span>个人身份与社会身份冲突时，容易出现误解或身份压力。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>personal identity 回答“我作为独特个体是谁”。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 social identity 区分：personal = individual uniqueness；social = group membership。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题可写：culture shapes identity, but individuals are not identical to culture。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>个人身份是“我为什么是这个独特的我”。</p>\n        </blockquote>\n      </div>\n    ",
  "gender": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>性别指社会和文化对男性、女性及其他性别身份所赋予的角色、期待、行为规范和身份意义。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Gender identity is different from biological sex or sexual identity, which is derived from anatomy at birth.</p><p>Gender is a socially constructed concept that refers to how a particular culture differentiates masculine and feminine social roles.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>性别身份不同于生物性别或性身份，后者来自出生时的身体解剖特征。</p><p>性别是一个社会建构概念，指特定文化如何区分男性化和女性化的社会角色。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：gender 是社会学、性别研究和跨文化交际中的基础概念；相关研究强调性别角色具有社会文化建构性。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>gender 是社会文化建构，不完全等同于 biological sex。</span>\n        \n      </li>\n    \n      <li>\n        <span>性别规范影响语言风格、礼貌方式、职业期待、家庭角色和身体表达。</span>\n        \n      </li>\n    \n      <li>\n        <span>不同文化、时代、阶层和群体对性别角色的期待不同。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，性别会影响谁可以说话、怎样说话、怎样表达情感和怎样进入公共空间。</span>\n        \n      </li>\n    \n      <li>\n        <span>性别角色差异可能导致礼貌、距离、眼神、触碰和权威表达的误解。</span>\n        \n      </li>\n    \n      <li>\n        <span>分析性别要同时看文化、权力和社会制度。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>sex 偏生理，gender 偏社会文化角色。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 gender 写成固定天性；课程重点是文化如何塑造性别期待。</span>\n        \n      </li>\n    \n      <li>\n        <span>可与 masculinity/femininity 区分：gender 是身份与角色，Hofstede 的 masculinity/femininity 是文化价值维度。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>sex 偏生理，gender 偏社会文化。</p>\n        </blockquote>\n      </div>\n    ",
  "ethnic-identity-ethnicity": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>族群身份是个体对某一族群的归属感和认同；族群性通常与共同祖先、历史记忆、语言、文化传统、宗教、地域或群体边界有关。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Ethnic identity, or ethnicity, is derived from a sense of shared heritage, history, traditions, values, similar behaviors, geographical area of origin, and in some cases language.</p><p>It may come from a nation-state or from a cultural grouping that transcends national borders and is grounded in shared cultural practices and beliefs.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>族群身份或族群性来自对共同遗产、历史、传统、价值观、相似行为、原属地域以及有时共同语言的感受。</p><p>它可能来自民族国家，也可能来自跨越国界、以共同文化实践和信念为基础的文化群体。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Fredrik Barth 强调族群边界；Jean Phinney 对 ethnic identity 发展研究影响较大。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>包含自我认同，也包含他人和社会对其的识别。</span>\n        \n      </li>\n    \n      <li>\n        <span>可以通过语言、饮食、服饰、仪式、节日、历史叙事和亲属关系表达。</span>\n        \n      </li>\n    \n      <li>\n        <span>族群身份是动态的，会因迁移、同化、歧视、代际变化而变化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>族群身份影响语言选择、群体归属、被代表方式和跨群体关系。</span>\n        \n      </li>\n    \n      <li>\n        <span>在移民、多元文化社会和少数族群经验中尤其重要。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中要区分对方如何自我认同与外界如何归类。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>ethnicity 不等于 race，也不等于 nationality。</span>\n        \n      </li>\n    \n      <li>\n        <span>族群身份既有文化线索，也有主观归属感。</span>\n        \n      </li>\n    \n      <li>\n        <span>可与 ascribed/avowed identity 联系：他人赋予的族群标签可能与本人自认不同。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>族群身份强调共同文化传统和归属感。</p>\n        </blockquote>\n      </div>\n    ",
  "national-character": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>国民性格是对某一国家成员常见行为倾向、价值叙事或性格特征的概括性描述。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>National character implies that members of a nation, despite ethnic, racial, religious, or individual differences, resemble one another in certain fundamental matters of belief and conduct more than they resemble members of other nations.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>国民性格指一个国家的成员虽然存在族群、种族、宗教或个人差异，但在某些基本信念和行为方面彼此相似，并且这种相似性超过他们与其他国家成员的相似性。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：国民性格研究与文化与人格学派、国家文化比较有关；Ruth Benedict 等学者曾做过相关研究，但该概念争议较大。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它通常来自历史叙事、媒体、教育、旅游经验和国家文化比较。</span>\n        \n      </li>\n    \n      <li>\n        <span>可以帮助理解一个国家的主流自我形象或外部形象。</span>\n        \n      </li>\n    \n      <li>\n        <span>但它高度概括，容易忽视国家内部的地区、阶层、族群、性别和个人差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，国民性格常影响第一印象和期待。</span>\n        \n      </li>\n    \n      <li>\n        <span>如果不加批判地使用，容易滑向刻板印象和民族中心主义。</span>\n        \n      </li>\n    \n      <li>\n        <span>较好的用法是把它当作文化叙事线索，而不是判断个人的证据。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>national character 很容易与 stereotype 混淆。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题时要强调它是概括，不可绝对化。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把国家等同于单一文化；国家内部也有多元文化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>国民性格可以参考，但不能套到每个人身上。</p>\n        </blockquote>\n      </div>\n    ",
  "ascribed-avowed-identities": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>赋予身份是他人、制度或社会标签归类给你的身份；自认身份是你自己承认、选择、声明或强调的身份。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Identities can be classified as ascribed or avowed based on how they are acquired, meaning whether an identity is obtained involuntarily or voluntarily.</p><p>Racial, ethnic, and sexual identities assigned at birth are often ascribed; an identity such as being a particular university student is avowed because it is voluntarily chosen.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>身份可以根据获得方式分为赋予身份和自认身份，也就是身份是非自愿获得还是自愿获得。</p><p>出生时被指定的种族、族群和性身份通常属于赋予身份；作为某所大学学生这样的身份属于自认身份，因为它是自愿选择的。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：这是跨文化交际身份研究中的常用区分，常见于身份协商和跨文化交际教材。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>ascribed identity 来自外部归类，例如口音、肤色、姓名、国籍、性别或制度身份。</span>\n        \n      </li>\n    \n      <li>\n        <span>avowed identity 来自自我定义，例如个人选择强调的族群、语言、职业或价值身份。</span>\n        \n      </li>\n    \n      <li>\n        <span>两者一致时沟通较顺畅，不一致时容易产生误读、冒犯或身份冲突。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，人们常根据外表或口音快速赋予身份。</span>\n        \n      </li>\n    \n      <li>\n        <span>尊重对方的 avowed identity 是减少偏见和误解的重要原则。</span>\n        \n      </li>\n    \n      <li>\n        <span>身份错认会影响信任、礼貌、权力关系和归属感。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>ascribed = others give you；avowed = you claim for yourself。</span>\n        <small class=\"translation\">ascribed 指别人赋予你的身份；avowed 指你自己声明或认同的身份。</small>\n      </li>\n    \n      <li>\n        <span>它与 stereotype 相关，但更关注身份归类与自我认同是否一致。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例中如果别人按标签定义某人，而本人不认同，可用该概念分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>ascribed 是别人给的身份，avowed 是自己认的身份。</p>\n        </blockquote>\n      </div>\n    ",
  "cultural-identity": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化身份是个体对某一文化群体的归属感、情感意义和自我定位，也包括他人通过语言、传统、规范和符号行为对其文化归属的识别。</p>\n        </section>\n        \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Scholars&#39; Definitions / 学者定义</h2>\n        <ul>\n      <li>\n        <span>Fong defines cultural identity through a shared system of symbolic verbal and nonverbal behavior meaningful to members with belonging, traditions, heritage, language, and norms.</span>\n        <small class=\"translation\">Fong 从共享的象征性言语与非言语行为系统、归属感、传统、遗产、语言和行为规范来界定文化身份。</small>\n      </li>\n    \n      <li>\n        <span>Ting-Toomey and Chung define cultural identity as the emotional significance attached to belonging or affiliation with a larger culture.</span>\n        <small class=\"translation\">Ting-Toomey 和 Chung 把文化身份定义为人们赋予对更大文化归属或依附感的情感意义。</small>\n      </li>\n    \n      <li>\n        <span>Klyukanov sees cultural identity as membership in a group sharing the same symbolic meanings.</span>\n        <small class=\"translation\">Klyukanov 将文化身份视为共享相同象征意义的群体成员身份。</small>\n      </li>\n    \n      <li>\n        <span>Dervin defines cultural identity as what people construct whenever they are in contact with other human beings.</span>\n        <small class=\"translation\">Dervin 认为文化身份是在与他人接触中不断建构出来的东西。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Function / 功能</h2>\n        <ul>\n      <li>\n        <span>Identity is increasingly a negotiation between what you call yourself and what others are willing to call you.</span>\n        <small class=\"translation\">身份越来越成为你如何称呼自己与别人愿意如何称呼你之间的协商。</small>\n      </li>\n    \n      <li>\n        <span>Cultural identity shapes expectations of appropriate communicative behaviors in social settings.</span>\n        <small class=\"translation\">文化身份塑造人们对不同社会场景中合适交际行为的理解与期待。</small>\n      </li>\n    \n      <li>\n        <span>Different expectations for identity display and communication style can create anxiety, misunderstandings, and conflict.</span>\n        <small class=\"translation\">身份展示和沟通风格期待不同，可能造成焦虑、误解和冲突。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Fong、Ting-Toomey、Chung、Klyukanov 和 Dervin 都从群体归属、符号意义和互动建构角度讨论 cultural identity。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>文化身份是抽象、复杂、动态并由社会建构的。</span>\n        \n      </li>\n    \n      <li>\n        <span>它包含共同传统、遗产、语言、规范、符号性言语与非言语行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>它不是固定标签，而是在自我称呼与他人归类之间不断协商。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化身份会塑造人们对合适交际行为、身份展示和沟通风格的期待。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化互动中，身份期待不同可能引发焦虑、误解甚至冲突。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解文化身份有助于避免把个体简化为国籍或族群标签。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>cultural identity 常考定义、动态性和社会建构性。</span>\n        \n      </li>\n    \n      <li>\n        <span>可与 social identity 区分：cultural identity 更强调共享符号系统、文化传统和归属感的情感意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题中涉及身份展示、归属感和他人归类时可调用。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化身份是我如何归属某种文化，以及别人如何识别这种归属。</p>\n        </blockquote>\n      </div>\n    ",
  "language": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>语言是由符号和规则构成的意义系统，是文化传递、身份表达、社会关系建构和跨文化沟通的核心工具。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Language may be thought of as an organized system of symbols, both verbal and nonverbal, used in a common and uniform way by people who can manipulate these symbols to express thoughts and feelings.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>语言可以被理解为一个有组织的符号系统，包含语言和非语言符号，由能够操控这些符号的人以共同且一致的方式用来表达思想和情感。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Language is an organized system of verbal and nonverbal symbols used in a common way to express thoughts and feelings.</span>\n        <small class=\"translation\">语言是一个有组织的符号系统，包括语言符号和非语言符号，人们以共同方式使用它们表达思想和情感。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Functions / 功能</h2>\n        <ul>\n      <li>\n        <span>Social interaction: language allows speaking, reading, writing, listening, thinking, emotion expression, stress relief, and invoking assistance.</span>\n        <small class=\"translation\">社会互动：语言使说、读、写、听、思考、表达情绪、缓解压力和寻求帮助成为可能。</small>\n      </li>\n    \n      <li>\n        <span>Social cohesion: a common language helps people form groups and cooperate.</span>\n        <small class=\"translation\">社会凝聚：共同语言帮助人们形成群体并合作。</small>\n      </li>\n    \n      <li>\n        <span>Expression of identity: language constructs individual, group, and cultural identity.</span>\n        <small class=\"translation\">身份表达：语言是建构个人、群体和文化身份的主要机制。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Characteristics / 特点</h2>\n        <ul>\n      <li>\n        <span>Words are only symbols.</span>\n        <small class=\"translation\">词语只是符号。</small>\n      </li>\n    \n      <li>\n        <span>Words are arbitrary.</span>\n        <small class=\"translation\">词语具有任意性。</small>\n      </li>\n    \n      <li>\n        <span>Words evoke denotative and connotative meanings.</span>\n        <small class=\"translation\">词语能唤起外延意义和内涵意义。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Edward Sapir 和 Benjamin Lee Whorf 与语言相对论相关；跨文化交际强调语言与文化相互塑造。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>语言反映文化：词汇、称呼、礼貌形式和隐喻体现文化价值。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言塑造经验：不同语言可能引导人们注意和分类世界的不同方面。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言表达身份、权力、亲疏、礼貌和群体归属。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化沟通中，翻译字面意义不等于理解文化意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言差异会影响请求、拒绝、道歉、赞美、幽默和沉默的解释。</span>\n        \n      </li>\n    \n      <li>\n        <span>双语或多语者常在语言选择中协商身份和关系。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>语言是 culture 的主要符号系统，但不是文化的全部。</span>\n        \n      </li>\n    \n      <li>\n        <span>Sapir-Whorf 常考语言与思维/文化关系。</span>\n        \n      </li>\n    \n      <li>\n        <span>denotative meaning 与 connotative meaning 是语言意义分析的重点。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>语言不只是说话工具，也是文化和身份的载体。</p>\n        </blockquote>\n      </div>\n    ",
  "denotative-connotative-meaning": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>外延意义是词语的字面、词典或基本指称意义；内涵意义是词语引发的情感色彩、社会评价、文化联想和隐含态度。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Denotative meaning is the literal, conventional meaning that most people in a culture have agreed is the meaning of a symbol.</p><p>Connotative meaning is the private, emotional meaning a word evokes, reflecting personal and cultural experiences and often creating difficulty in intercultural exchanges.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>外延意义是一个文化中大多数人约定的符号字面、常规意义。</p><p>内涵意义是词语唤起的私人、情感性意义，反映个人和文化经验，并常在跨文化交流中造成理解困难。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：这是语义学和符号学中的基础区分，跨文化交际用它解释词语文化含义差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>denotative meaning 相对直接，回答“它指什么”。</span>\n        \n      </li>\n    \n      <li>\n        <span>connotative meaning 更依赖文化经验，回答“它让人联想到什么、感觉如何”。</span>\n        \n      </li>\n    \n      <li>\n        <span>同一词语外延相近，内涵可能因文化和语境而差异很大。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化误解常来自只翻译外延，忽略内涵。</span>\n        \n      </li>\n    \n      <li>\n        <span>颜色、动物、称呼、数字、礼貌词和幽默常带有强烈文化内涵。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解内涵意义有助于避免无意冒犯和错误联想。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>外延看字面，内涵看联想和情感色彩。</span>\n        \n      </li>\n    \n      <li>\n        <span>翻译题和案例题常考 connotation。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 connotation 写成“错误意义”；它是文化和情感层面的附加意义。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>denotation 是字面指称，connotation 是文化联想。</p>\n        </blockquote>\n      </div>\n    ",
  "nonverbal-communication": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>非语言沟通是不依靠词语本身传递意义的沟通方式，包括表情、眼神、姿势、手势、身体距离、触碰、沉默、时间使用和外表等。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Nonverbal communication involves all nonverbal stimuli in a communication setting that are generated by both the source and the source&#39;s use of the environment and that have potential message value for the source and/or receiver.</p><p>It includes intentional and unintentional messages and the reciprocal relationship between verbal and nonverbal messages.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>非语言沟通包括交际情境中由信息来源及其对环境的使用所产生的所有非语言刺激，这些刺激对发送者和/或接收者具有潜在信息价值。</p><p>它包括有意和无意的信息，也包括语言信息与非语言信息之间的相互关系。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Nonverbal communication involves all nonverbal stimuli in a communication setting that are generated by source and environment and have potential message value.</span>\n        <small class=\"translation\">非言语交际包括交际环境中由来源和环境产生并具有潜在信息价值的所有非言语刺激。</small>\n      </li>\n    \n      <li>\n        <span>It includes intentional and unintentional messages and the reciprocal relationship between verbal and nonverbal messages.</span>\n        <small class=\"translation\">它包括有意与无意的信息，以及语言信息和非语言信息之间的相互关系。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Functions / 功能</h2>\n        <ul>\n      <li>\n        <span>Convey internal states.</span>\n        <small class=\"translation\">传达内部状态。</small>\n      </li>\n    \n      <li>\n        <span>Create identity.</span>\n        <small class=\"translation\">创造身份。</small>\n      </li>\n    \n      <li>\n        <span>Regulate interaction.</span>\n        <small class=\"translation\">调节互动。</small>\n      </li>\n    \n      <li>\n        <span>Substitute for words.</span>\n        <small class=\"translation\">替代文字。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>Characteristics and Classes / 特点与分类</h2>\n        <ul>\n      <li>\n        <span>Nonverbal communication is multichannel, often ambiguous, and influenced by numerous variables.</span>\n        <small class=\"translation\">非语言交际是多渠道的，通常模棱两可，并受许多变量影响。</small>\n      </li>\n    \n      <li>\n        <span>Classes include body messages, appearance, body movement, space and distance, time, and silence.</span>\n        <small class=\"translation\">分类包括肢体信息、外貌、身体动作、空间与距离、时间和沉默。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：非语言沟通是传播学重要领域；Edward T. Hall 对空间、时间和语境研究影响很大。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>非语言信号常与文化规则密切相关。</span>\n        \n      </li>\n    \n      <li>\n        <span>它可以补充、重复、强调、替代或矛盾语言信息。</span>\n        \n      </li>\n    \n      <li>\n        <span>非语言信号通常多义，必须结合语境解释。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>不同文化对眼神、微笑、沉默、触碰、距离和手势的解释可能不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>高语境沟通中，非语言线索尤其重要。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中，非语言误读往往比词汇错误更容易伤害关系。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>nonverbal 不等于 universal；很多非语言信号不是全球通用。</span>\n        \n      </li>\n    \n      <li>\n        <span>paralanguage、proxemics、chronemics 都属于或关联非语言沟通。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题可从 eye contact、gesture、silence、space、time 分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>不说话，也在沟通。</p>\n        </blockquote>\n      </div>\n    ",
  "paralanguage": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>副语言是语言词义之外的声音特征，如语调、音高、音量、语速、停顿、重音、笑声、叹息和沉默。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Paralanguage includes all oral cues in the stream of spoken utterances except the words themselves.</p><p>Most classifications divide it into vocal qualities, vocal characterizers, and vocal segregates.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>副语言包括口语话流中除词语本身之外的所有口头线索。</p><p>多数分类把它分为嗓音质量、嗓音特征和嗓音分离成分。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：George L. Trager 的副语言研究常被视为 paralanguage 概念发展的重要来源。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它不改变词典意义，却会改变态度、情绪和关系意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>同一句话因语气不同，可以表达真诚、讽刺、命令、怀疑或亲密。</span>\n        \n      </li>\n    \n      <li>\n        <span>副语言与文化密切相关，例如沉默、音量和停顿的合适程度不同。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，语速、音量或沉默可能被误解为粗鲁、冷漠、自信或不诚实。</span>\n        \n      </li>\n    \n      <li>\n        <span>副语言帮助判断话语背后的情绪和关系意图。</span>\n        \n      </li>\n    \n      <li>\n        <span>听懂 words 不等于听懂 how it is said。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>paralanguage 属于 nonverbal communication 中与声音有关的部分。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 paralanguage 写成 vocabulary 或 grammar。</span>\n        \n      </li>\n    \n      <li>\n        <span>常考例子：tone、pitch、volume、rate、pause、silence。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>副语言是话语的声音表情。</p>\n        </blockquote>\n      </div>\n    ",
  "proxemics": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>空间语言学研究人们如何使用身体距离和空间安排来表达关系、身份、亲密程度、隐私、权力和文化规范。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Proxemics is the study of the message system created by distance and space in communication.</p><p>Hall defines proxemics as the interrelated observations and theories of human use of space as a specialized elaboration of culture; today it includes personal space, seating, and furniture arrangement.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>空间语言学研究沟通中由距离和空间形成的信息系统。</p><p>霍尔把空间语言学定义为关于人类如何使用空间的一组相互关联的观察和理论，认为空间使用是文化的特殊展开；今天它包括个人空间、座位和家具安排。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Proxemics is the study of the message system created by variation in distance between people.</span>\n        <small class=\"translation\">人际距离学研究人与人之间距离变化所形成的信息系统。</small>\n      </li>\n    \n      <li>\n        <span>Hall defines proxemics as interrelated observations and theories of human use of space as a specialized elaboration of culture.</span>\n        <small class=\"translation\">霍尔把人际距离学定义为关于人类使用空间的一组相互关联的观察和理论，认为空间使用是文化的特殊展开。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Focus / 关注点</h2>\n        <ul>\n      <li>\n        <span>personal space, seating, and furniture arrangement</span>\n        <small class=\"translation\">个人空间、座位安排和家具布置。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Edward T. Hall。proxemics 是 Hall 对人际距离和空间使用的研究概念。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>Hall 常区分亲密距离、个人距离、社交距离和公共距离。</span>\n        \n      </li>\n    \n      <li>\n        <span>空间距离的合适程度因文化、关系、场合、性别和权力而不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>空间使用不仅包括站多远，也包括座位安排、领地感和私人空间。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>距离过近可能被认为冒犯或侵犯隐私，距离过远可能被认为冷淡或疏离。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中，空间规则差异常出现在问候、排队、会议和课堂互动中。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解 proxemics 有助于解释身体距离带来的舒适或不适。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>proxemics 是空间距离，不是 power distance。</span>\n        \n      </li>\n    \n      <li>\n        <span>提出人是 Hall。</span>\n        \n      </li>\n    \n      <li>\n        <span>关键词：space、distance、personal space、territory、intimacy。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>人和人站多远，也是一种文化信息。</p>\n        </blockquote>\n      </div>\n    ",
  "monochronic-polychronic-time": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>单时制/多时制描述文化如何组织时间：单时制强调线性计划和一次做一件事，多时制强调关系、弹性和多任务并行。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Hall proposed that cultures organize time in two broad ways: monochronic time and polychronic time.</p><p>M-time views time as linear, sequential, segmented, and schedule-based, with one thing done at a time; P-time treats relationships rather than tasks as central, uses time flexibly, and may involve several people or activities at once.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>霍尔提出，文化大体上以两种方式组织时间：单时制和多时制。</p><p>单时制把时间看作线性、连续、可分割并由日程安排管理，强调一次做一件事；多时制以关系而非任务为中心，灵活使用时间，并可能同时处理多人或多项活动。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Hall proposed that cultures organize time as monochronic time or polychronic time, best understood as points along a continuum.</span>\n        <small class=\"translation\">霍尔提出文化以单时制或多时制组织时间，更现实的理解是把二者看作连续体上的点。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>M-time / 单时制</h2>\n        <ul>\n      <li>\n        <span>M-time views time as a scarce resource controlled through schedules and appointments, with one thing done at a time.</span>\n        <small class=\"translation\">单时制把时间视为稀缺资源，通过日程和预约控制时间，并强调一次只做一件事。</small>\n      </li>\n    \n      <li>\n        <span>M-time values punctuality, product over process, and careful use of time.</span>\n        <small class=\"translation\">单时制重视准时、结果优先于过程，以及审慎使用时间。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-o\">\n        <h2>P-time / 多时制</h2>\n        <ul>\n      <li>\n        <span>P-time cultures deal with life more holistically; time is less tangible and people can interact with several people or activities at once.</span>\n        <small class=\"translation\">多时制文化更整体地处理生活；时间不那么有形，人们可以同时与多人互动或处理多项活动。</small>\n      </li>\n    \n      <li>\n        <span>This multitasking orientation helps explain more interruptions in Arabic, Asian, and Latin American conversations.</span>\n        <small class=\"translation\">这种多任务倾向解释了阿拉伯、亚洲和拉美文化谈话中较多打断现象。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>提出人：Edward T. Hall。该区分属于 Hall 对文化时间取向的研究。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>monochronic time：重日程、准时、计划、效率、顺序和截止时间。</span>\n        \n      </li>\n    \n      <li>\n        <span>polychronic time：重关系、弹性、情境变化、多任务和人际义务。</span>\n        \n      </li>\n    \n      <li>\n        <span>这不是守时与不守时的道德差异，而是时间优先级不同。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化合作中，对迟到、会议时长、截止日期和临时变更的理解可能不同。</span>\n        \n      </li>\n    \n      <li>\n        <span>单时制文化可能把时间看作可分割、可管理的资源。</span>\n        \n      </li>\n    \n      <li>\n        <span>多时制文化可能把关系和情境需要置于固定日程之上。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>Hall，不是 Hofstede。</span>\n        \n      </li>\n    \n      <li>\n        <span>M-time 看 schedule；P-time 看 relationships。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 polychronic 简化成懒散或不守信用。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>M-time 看时间表，P-time 看关系网。</p>\n        </blockquote>\n      </div>\n    ",
  "silence": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>沉默是交际过程中没有使用话语但仍可能承载意义的非语言行为，它可以提供思考、情绪控制、反馈、礼貌或不满表达的空间。</p>\n        </section>\n        \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>In interpersonal settings, silence provides an interval during which participants can think, suppress emotion, encode a lengthy response, begin another line of thought, emphasize words, express emotions, or indicate thoughtfulness.</span>\n        <small class=\"translation\">在人际情境中，沉默为参与者提供时间去思考、抑制情绪、组织较长回应、开启另一思路、强调某些词语、表达情绪或表示深思熟虑。</small>\n      </li>\n    \n      <li>\n        <span>Silence also provides feedback about the clarity or significance of an idea in the overall exchange.</span>\n        <small class=\"translation\">沉默也能提供反馈，提示某个想法在整体交流中的清晰度或重要性。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：silence 属于非语言交际研究中的重要概念，常与 Hall 的高低语境理论一起分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>沉默可以表示深思、尊重、尴尬、拒绝、同意、不满或等待，意义依赖语境。</span>\n        \n      </li>\n    \n      <li>\n        <span>高语境文化通常更能通过沉默、停顿和非语言线索传递意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>低语境文化可能更容易把沉默理解为缺乏回应、信息不足或不礼貌。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，沉默的误读会导致对礼貌、态度和能力的错误判断。</span>\n        \n      </li>\n    \n      <li>\n        <span>分析沉默时要同时看关系、权力、场合、文化语境和交际目的。</span>\n        \n      </li>\n    \n      <li>\n        <span>沉默也可作为反馈，让双方判断观点是否清楚或是否重要。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>silence 属于 nonverbal communication。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把沉默一律解释为无话可说；它可能是礼貌、思考或冲突回避。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例中看到对方不回答、停顿或回避直接表态，可从 high-context 与 facework 分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>沉默不是没有意义，而是意义没有用话语说出来。</p>\n        </blockquote>\n      </div>\n    ",
  "culture-shock": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化冲击是进入陌生文化环境后，因为语言、规则、价值、社会线索和日常习惯不同而产生的压力、困惑、焦虑和适应困难。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>A sojourner entering a new cultural environment for a sustained period usually experiences some degree of culture shock.</p><p>Culture shock reactions may be affective, behavioral, and cognitive, including disorientation, rejection, homesickness, withdrawal, irritation, fatigue, and sometimes depression.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>旅居者在较长时间进入新的文化环境时，通常会经历某种程度的文化冲击。</p><p>文化冲击的反应可能体现在情感、行为和认知层面，包括迷失方向、被排斥感、想家、退缩、烦躁、疲惫，有时甚至抑郁。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Culture shock is precipitated by anxiety from losing familiar signs and symbols of social intercourse, such as words, gestures, facial expressions, customs, and norms.</span>\n        <small class=\"translation\">文化冲击由失去熟悉的社会交往标志和符号所引起的焦虑触发，例如言语、手势、面部表情、习俗和规范。</small>\n      </li>\n    \n      <li>\n        <span>It disrupts routines, ego, and self-image.</span>\n        <small class=\"translation\">它会强烈扰乱日常生活、自我和自我形象。</small>\n      </li>\n    </ul>\n      </section>\n    \n      <section class=\"card card-g\">\n        <h2>Process / 过程</h2>\n        <ul>\n      <li>\n        <span>Culture shock is not one-time; it is a repetitive process of increasingly subtle immersion into a culture.</span>\n        <small class=\"translation\">文化冲击不是一次性现象，而是不断、更细微地融入文化的重复过程。</small>\n      </li>\n    \n      <li>\n        <span>It often involves taking two steps forward and one step back.</span>\n        <small class=\"translation\">它常表现为前进两步、后退一步。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Kalervo Oberg 系统讨论 culture shock，是跨文化适应研究中最常引用的来源之一。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>常见阶段：蜜月期、挫折期、恢复期、适应期。</span>\n        \n      </li>\n    \n      <li>\n        <span>表现为孤独、疲惫、焦虑、误解增多、身份不稳定和对原文化的强烈依恋。</span>\n        \n      </li>\n    \n      <li>\n        <span>它通常是跨文化适应过程的一部分，不代表个人失败。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化冲击说明文化规则在日常生活中具有强大影响。</span>\n        \n      </li>\n    \n      <li>\n        <span>理解文化冲击可以帮助留学生、移民和跨国工作者建立合理期待。</span>\n        \n      </li>\n    \n      <li>\n        <span>通过学习文化规则、建立支持网络、反思自我和调整沟通方式可以缓解。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>culture shock 偏短中期心理和行为反应；acculturation 是更长期的文化适应过程。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要只写“想家”，要写 unfamiliar cultural environment 带来的 stress。</span>\n        \n      </li>\n    \n      <li>\n        <span>常考阶段和缓解方式。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>熟悉的文化规则突然失效时，就会产生文化冲击。</p>\n        </blockquote>\n      </div>\n    ",
  "acculturation": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化适应是不同文化群体持续接触后，个体或群体在价值观、行为、身份和生活方式上发生调整和变化的过程。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Acculturation is the process of learning to become functional and comfortable in a new cultural setting.</p><p>It can be understood as a continuing process of stress, adaptation, and growth in which sojourners develop and incorporate the cultural norms needed to function competently.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>文化适应是学习在新的文化环境中有效生活并感到舒适的过程。</p><p>它可以理解为一个持续的压力、适应和成长过程；旅居者在其中发展并吸收必要的文化规范，以便在新环境中胜任生活和交际。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Acculturation is the adoption of behavior patterns of the surrounding culture.</span>\n        <small class=\"translation\">文化适应是采纳周围文化行为模式的过程。</small>\n      </li>\n    \n      <li>\n        <span>It is a continuing process of stress-adaptation-growth.</span>\n        <small class=\"translation\">它是持续的“压力-适应-成长”过程。</small>\n      </li>\n    \n      <li>\n        <span>After entering a different culture, people experience stress and then learn to adapt if culture shock is not severe.</span>\n        <small class=\"translation\">进入不同文化后，人们会在面对新程序、行为和交际标准时经历压力；如果文化冲击不严重，便开始学习适应新文化。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>经典定义来自 Redfield、Linton 和 Herskovits；John W. Berry 提出常用的四种文化适应策略。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>integration：保持原文化，同时参与新文化。</span>\n        \n      </li>\n    \n      <li>\n        <span>assimilation：弱化原文化，主要融入主流文化。</span>\n        \n      </li>\n    \n      <li>\n        <span>separation：保持原文化，较少参与新文化。</span>\n        \n      </li>\n    \n      <li>\n        <span>marginalization：与原文化和新文化都缺乏稳定连接。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化适应常见于移民、留学、跨国婚姻、跨国工作和少数族群处境。</span>\n        \n      </li>\n    \n      <li>\n        <span>适应不只是个人努力，也受主流社会接纳程度、制度和权力关系影响。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化交际中，适应过程会改变语言选择、身份认同和社交网络。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>acculturation 比 culture shock 更长期、更结构化。</span>\n        \n      </li>\n    \n      <li>\n        <span>assimilation 不等于 integration：前者弱化原文化，后者双向保持和参与。</span>\n        \n      </li>\n    \n      <li>\n        <span>Berry 四策略是高频考点。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化冲击是反应，文化适应是长期调整过程。</p>\n        </blockquote>\n      </div>\n    ",
  "stereotyping": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>刻板印象是对某一群体形成固定、简化、过度概括的看法，并把这种看法直接套用到个体身上。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Stereotyping is a complex form of categorization that mentally organizes one&#39;s experiences with and guides behavior toward a particular group of people.</p><p>A stereotype is a cognitive structure containing the perceiver&#39;s knowledge, beliefs, and expectancies about some human social groups; problems arise when people overgeneralize.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>刻板印象是一种复杂的分类形式，它在心理上组织人们与某一群体有关的经验，并引导人们对该群体的行为。</p><p>刻板印象是一种认知结构，包含感知者对某些人类社会群体的知识、信念和期待；当人们过度概括时就会产生问题。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Stereotyping is a complex form of categorization that mentally organizes experiences and guides behavior toward a particular group.</span>\n        <small class=\"translation\">刻板印象是一种复杂的分类形式，它在心理上组织经验，并引导人们对特定群体的行为。</small>\n      </li>\n    \n      <li>\n        <span>A stereotype is a cognitive structure containing knowledge, beliefs, and expectancies about social groups.</span>\n        <small class=\"translation\">刻板印象是包含对某些社会群体的知识、信念和期待的认知结构。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Walter Lippmann 将 stereotype 引入社会舆论和社会认知讨论。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它是一种认知捷径，可以减少信息处理负担，但会牺牲准确性。</span>\n        \n      </li>\n    \n      <li>\n        <span>它忽视群体内部差异和具体情境。</span>\n        \n      </li>\n    \n      <li>\n        <span>刻板印象可以是负面的，也可以看似正面，但都会限制真实理解。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，刻板印象会影响第一印象、期待、倾听方式和解释方向。</span>\n        \n      </li>\n    \n      <li>\n        <span>它可能导致自证预言：人们只注意符合标签的信息。</span>\n        \n      </li>\n    \n      <li>\n        <span>减少刻板印象需要接触真实个体、理解语境并保持可修正性。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>stereotype 比 generalization 更僵化、更难修正。</span>\n        \n      </li>\n    \n      <li>\n        <span>关键词：fixed、oversimplified、all members、label。</span>\n        \n      </li>\n    \n      <li>\n        <span>刻板印象是认知层面；prejudice 是态度情绪层面；discrimination 是行为层面。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>刻板印象把复杂的人压成简单标签。</p>\n        </blockquote>\n      </div>\n    ",
  "prejudices": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>偏见是在充分了解之前，基于群体身份对某一群体或其成员形成的负面态度、情绪或评价。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Prejudice is an unfounded attitude toward an outgroup based on comparison with one&#39;s ingroup.</p><p>It is often displayed through group labels, hostile humor, or vocabulary that stresses the superiority of one group over another, and negative feelings and attitudes are central to it.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>偏见是基于与内群体比较而形成的、针对外群体的无根据态度。</p><p>它常通过群体标签、敌对幽默或强调某一群体优越于另一群体的词汇表现出来，负面情感和态度是其核心部分。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Prejudices are deeply held negative feelings associated with a particular group, including anger, fear, aversion, and anxiety.</span>\n        <small class=\"translation\">偏见是与特定群体相关的根深蒂固的负面感受，包括愤怒、恐惧、厌恶和焦虑。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Gordon Allport 的 The Nature of Prejudice 是偏见研究的重要经典。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>偏见主要是 attitude，包含情绪和评价成分。</span>\n        \n      </li>\n    \n      <li>\n        <span>它常建立在刻板印象之上，并可能导致歧视行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>偏见可能公开表达，也可能以隐性偏见形式影响判断。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，偏见会降低信任、阻碍倾听，并让中性行为被负面解释。</span>\n        \n      </li>\n    \n      <li>\n        <span>偏见常与权力、历史冲突、媒体叙事和社会制度相互强化。</span>\n        \n      </li>\n    \n      <li>\n        <span>识别偏见需要区分事实观察与带有情绪评价的判断。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>prejudice 是态度，stereotype 是认知，discrimination 是行为。</span>\n        \n      </li>\n    \n      <li>\n        <span>prejudice 不一定已经表现为行动，但会影响解释和选择。</span>\n        \n      </li>\n    \n      <li>\n        <span>看到 negative attitude before knowing enough，多半是 prejudice。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>偏见是还没了解，就先带着负面态度看人。</p>\n        </blockquote>\n      </div>\n    ",
  "racism": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>种族主义是基于种族分类对群体进行等级化，并通过观念、话语、制度或行为制造和维持特权、排斥与压迫的体系。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Racism appears in both blatant and subtle forms at organizational and personal levels.</p><p>Minority groups may be subjected to racism because of perceived biological differences, usually physical appearance; racism excludes selected groups from social, economic, and educational institutions and damages both identities and social cohesion.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>种族主义既可能以公开形式出现，也可能以隐蔽形式存在于组织层面和个人层面。</p><p>少数群体可能因为被感知到的生理差异，尤其是外貌差异而遭受种族主义；种族主义会把特定群体排除在社会、经济和教育制度之外，并损害身份认同和社会凝聚力。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Racism is an extension of stereotyping and prejudice: belief in the inherent superiority of a particular race.</span>\n        <small class=\"translation\">种族主义是刻板印象和偏见的延伸，即相信某一种族具有固有优越性。</small>\n      </li>\n    \n      <li>\n        <span>It denies basic human equality and correlates ability with physical composition.</span>\n        <small class=\"translation\">它否认人类基本平等，并把能力与身体构成联系起来。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：racism 是社会学、历史学和批判种族研究中的核心概念，现代研究强调其与权力和制度有关。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它把身体特征或被建构的种族类别与能力、道德、文明程度或社会价值错误关联。</span>\n        \n      </li>\n    \n      <li>\n        <span>它不仅是个人偏见，也可能存在于法律、教育、住房、就业、媒体和语言结构中。</span>\n        \n      </li>\n    \n      <li>\n        <span>racism 通常涉及 prejudice + power，即负面态度与权力结构结合。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中，种族主义影响谁被相信、谁有话语权、谁被要求适应、谁被代表。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言、玩笑、称呼和媒体形象都可能复制种族化意义。</span>\n        \n      </li>\n    \n      <li>\n        <span>分析跨文化冲突时，需要同时看文化差异和权力不平等。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>racism 不只是个人不喜欢某群体，还包括制度性和结构性层面。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要把 racism 简化成 race difference；重点是等级化和权力。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 prejudice 区分：偏见是态度，种族主义强调种族化权力体系。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>种族主义是把种族差异变成等级和权力差异。</p>\n        </blockquote>\n      </div>\n    ",
  "power": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>权力是影响他人行为、控制资源、制定规则、定义意义并决定谁有话语权的能力。</p>\n        </section>\n        \n      <section class=\"card card-r source-definition\">\n        <h2>英文定义 / 中文翻译</h2>\n        <div class=\"grid grid-2 source-grid\">\n          <div>\n            <h3>English<small>英文</small></h3>\n            <p>Max Weber considered power as the ability to exert one&#39;s will even in the face of opposition.</p><p>More broadly, power is the ability to cause things to happen, to control what happens, and to prevent things one does not want to happen.</p>\n          </div>\n          <div>\n            <h3>中文翻译</h3>\n            <p>马克斯·韦伯把权力理解为即使面对反对也能贯彻自身意志的能力。</p><p>更广义地说，权力是促使事情发生、控制发生的事情，以及防止不希望发生的事情的能力。</p>\n          </div>\n        </div>\n      </section>\n    \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Max Weber considered power as the ability to exert one&#39;s will even in the face of opposition.</span>\n        <small class=\"translation\">马克斯·韦伯认为权力是即使面对反对也能贯彻自身意志的能力。</small>\n      </li>\n    \n      <li>\n        <span>Power is the ability to cause things to happen, control what happens, and prevent things one does not want.</span>\n        <small class=\"translation\">更广义地说，权力是促使事情发生、控制发生的事，并防止不想发生的事的能力。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Max Weber 将权力理解为让他人按自己意愿行动的可能性；Michel Foucault 强调权力也存在于话语和知识生产中。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>权力可来自职位、财富、知识、语言能力、制度、身份、文化资本或话语资源。</span>\n        \n      </li>\n    \n      <li>\n        <span>权力既存在于个人互动中，也存在于组织、制度和社会结构中。</span>\n        \n      </li>\n    \n      <li>\n        <span>权力不只压迫，也会塑造什么被认为是正常、正确和有价值。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际不是平等真空中的文化差异交换，权力会影响谁需要适应谁。</span>\n        \n      </li>\n    \n      <li>\n        <span>语言优势、主流文化地位、国籍、种族、性别和阶层都会影响交际权力。</span>\n        \n      </li>\n    \n      <li>\n        <span>分析文化误解时，要同时看意义差异和权力差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>power 不等于 power distance：power 是影响力本身，power distance 是对权力不平等的接受程度。</span>\n        \n      </li>\n    \n      <li>\n        <span>答题关键词：resources、control、authority、discourse、voice、inequality。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题中如果有人能定义规则、评价他人或要求他人适应，就涉及 power。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>权力决定谁能制定规则、解释意义和被认真听见。</p>\n        </blockquote>\n      </div>\n    ",
  "intercultural-ethics": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>伦理是在面对困难道德选择时用来判断和行动的原则工具；跨文化语境中的伦理尤其关注如何在冲突权利、文化差异和共同人性之间作出负责选择。</p>\n        </section>\n        \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Ethics is a tool used when making difficult moral choices.</span>\n        <small class=\"translation\">伦理是做出困难道德选择时可以使用的工具。</small>\n      </li>\n    \n      <li>\n        <span>These choices often balance competing rights when there does not appear to be one correct answer.</span>\n        <small class=\"translation\">当似乎没有唯一正确答案时，这些选择往往需要平衡相互竞争的权利。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：ethics 是跨文化交际中处理价值冲突和道德选择的基础工具。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>伦理选择常发生在没有唯一正确答案、需要平衡竞争性权利的时候。</span>\n        \n      </li>\n    \n      <li>\n        <span>跨文化伦理要求尊重个体价值、承认差异合理性，并意识到沟通具有影响力。</span>\n        \n      </li>\n    \n      <li>\n        <span>它不等于简单迎合任何文化，也不等于用本文化标准压倒他文化。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>跨文化交际中的伦理帮助人们避免民族中心主义、文化霸权和无原则相对主义。</span>\n        \n      </li>\n    \n      <li>\n        <span>它要求交际者在尊重差异的同时承担自己行动的后果。</span>\n        \n      </li>\n    \n      <li>\n        <span>讨论文化冲突时，伦理视角可以补充权力、身份和价值分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>ethics 可与 cultural relativism、universalism 一起考。</span>\n        \n      </li>\n    \n      <li>\n        <span>关键词：moral choices、competing rights、responsibility、respect。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题结尾提出建议时，可加入尊重个体、寻找共同点和承认差异。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>伦理是在文化差异中负责任地做选择。</p>\n        </blockquote>\n      </div>\n    ",
  "cultural-relativism": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化相对主义认为伦理系统和文化规范会因文化而异，不同系统各有其内部合理性，不能简单用单一文化标准判断所有文化。</p>\n        </section>\n        \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Cultural relativism is based on the belief that ethical systems vary among cultures, all systems are equally valid, and no single system is better than others.</span>\n        <small class=\"translation\">文化相对主义相信伦理系统会因文化而异，所有系统同样有效，没有单一系统优于其他系统。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>代表学者：Franz Boas 和后续人类学传统常与文化相对主义联系在一起。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它反对民族中心主义，要求把行为放回其文化语境中理解。</span>\n        \n      </li>\n    \n      <li>\n        <span>它强调不同文化系统都可能有效，而非天然高低有别。</span>\n        \n      </li>\n    \n      <li>\n        <span>过度相对主义可能难以处理伤害、压迫或基本权利冲突。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>文化相对主义能帮助交际者暂缓评价、理解差异并减少误解。</span>\n        \n      </li>\n    \n      <li>\n        <span>它鼓励先问“这一行为在对方文化中意味着什么”，再作判断。</span>\n        \n      </li>\n    \n      <li>\n        <span>在伦理困境中，需要与普遍主义、人权和责任意识一起平衡。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>relativism 与 universalism 是一对高频对比。</span>\n        \n      </li>\n    \n      <li>\n        <span>relativism 强调文化语境和多种伦理系统的有效性。</span>\n        \n      </li>\n    \n      <li>\n        <span>不要写成“任何行为都必须接受”；更准确是先理解语境，再进行审慎伦理判断。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化相对主义先把行为放回文化语境中理解。</p>\n        </blockquote>\n      </div>\n    ",
  "cultural-universalism": "\n      <div class=\"reply\">\n        <section class=\"tldr\">\n          <h2>核心定义</h2>\n          <p>文化普遍主义认为无论人、语境、时间或地点如何，都存在适用于所有文化的普遍伦理原则或基本规范。</p>\n        </section>\n        \n        \n      <section class=\"paper-section memorization-block\">\n        <div class=\"paper-section-head\">\n          <div>\n            <h2>背诵版匹配要点</h2>\n            <p>来自《跨文化交际背诵版(2)(1).docx》，按当前概念页逐项匹配。</p>\n          </div>\n          <span>DOCX</span>\n        </div>\n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-b\">\n        <h2>Definition / 定义</h2>\n        <ul>\n      <li>\n        <span>Cultural universalism is opposed to relativism and maintains that immutable universal ethical precepts apply to all cultures regardless of people, context, time, or place.</span>\n        <small class=\"translation\">文化普遍主义与相对主义相对，认为无论人、语境、时间或地点如何，都存在适用于所有文化的不变普遍伦理准则。</small>\n      </li>\n    </ul>\n      </section>\n    \n        </div>\n      </section>\n    \n        <div class=\"grid grid-2\">\n          \n      <section class=\"card card-p\">\n        <h2>提出人 / 代表学者</h2>\n        <ul>\n      <li>\n        <span>无单一提出人：universalism 是伦理学和跨文化伦理讨论中的基础立场。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-b\">\n        <h2>主要特征</h2>\n        <ul>\n      <li>\n        <span>它与文化相对主义相对，强调跨文化的共同道德底线。</span>\n        \n      </li>\n    \n      <li>\n        <span>它常用于讨论基本人权、人的尊严、公正和不可伤害等问题。</span>\n        \n      </li>\n    \n      <li>\n        <span>过度普遍主义可能忽视具体文化语境，并被误用为本文化优越感。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-g\">\n        <h2>跨文化交际意义</h2>\n        <ul>\n      <li>\n        <span>普遍主义帮助跨文化交际者在差异之外寻找共同伦理基础。</span>\n        \n      </li>\n    \n      <li>\n        <span>它可以防止以文化差异为名合理化伤害、压迫和不平等。</span>\n        \n      </li>\n    \n      <li>\n        <span>实际分析中应结合语境理解与共同原则，避免相对主义或民族中心主义两个极端。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n          \n      <section class=\"card card-o\">\n        <h2>考试辨析</h2>\n        <ul>\n      <li>\n        <span>universalism 强调 immutable universal ethical precepts。</span>\n        \n      </li>\n    \n      <li>\n        <span>与 relativism 区分：前者找共同伦理原则，后者强调文化内部合理性。</span>\n        \n      </li>\n    \n      <li>\n        <span>案例题涉及权利冲突时，可用 relativism + universalism 平衡分析。</span>\n        \n      </li>\n    </ul>\n      </section>\n    \n        </div>\n        <blockquote>\n          <p>文化普遍主义相信差异之外仍有共同伦理底线。</p>\n        </blockquote>\n      </div>\n    "
};
});
